function closeTaskActionMenu() {
  if (!activeTaskActionMenu) return;

  activeTaskActionMenu.anchorElement?.classList.remove("open");
  activeTaskActionMenu.anchorElement?.classList.remove("open-upwards");
  activeTaskActionMenu.anchorElement?.classList.remove("schedule-open");
  activeTaskActionMenu.anchorElement?.classList.remove("tag-open");
  activeTaskActionMenu.anchorElement?.classList.remove("tag-create-open");
  activeTaskActionMenu.anchorElement?.classList.remove("postpone-open");
  activeTaskActionMenu.taskElement?.classList.remove("menu-open");
  activeTaskActionMenu.hostColumn?.classList.remove("task-focus-host");
  activeTaskActionMenu.overlayElement?.remove();
  document.body.classList.remove("task-action-focus");
  activeTaskActionMenu = null;
}

function positionTaskActionMenu(anchorElement) {
  const menuElement = anchorElement?.querySelector(".task-menu-stack");
  if (!menuElement) return;

  const taskElement = anchorElement.closest(".task");
  const taskRect = taskElement?.getBoundingClientRect();
  const dayOverlayContainer = anchorElement.closest("#dayOverlay.day-overlay-cardless .day-overlay-column");
  const containerModal = dayOverlayContainer ? null : anchorElement.closest("#dayOverlay .modal");
  anchorElement.classList.remove("open-upwards");
  anchorElement.classList.remove("side-open-left");

  const sidePanels = anchorElement.querySelectorAll(".task-side-panel");

  // Reset previous clamping before measuring natural sizes.
  menuElement.style.maxHeight = "none";
  menuElement.style.overflowY = "visible";
  sidePanels.forEach((panel) => {
    panel.style.maxHeight = "none";
    panel.style.overflowY = "visible";
  });

  const anchorRect = anchorElement.getBoundingClientRect();
  const menuHeight = menuElement.offsetHeight;
  const gap = 16;
  const viewportPadding = dayOverlayContainer ? 18 : 24;
  const boundaryPadding = containerModal ? 20 : viewportPadding;
  const boundaryRect = containerModal?.getBoundingClientRect();
  const topBoundary = boundaryRect
    ? boundaryRect.top + boundaryPadding
    : viewportPadding;
  const bottomBoundary = boundaryRect
    ? boundaryRect.bottom - boundaryPadding
    : window.innerHeight - viewportPadding;
  const leftBoundary = boundaryRect
    ? boundaryRect.left + boundaryPadding
    : viewportPadding;
  const rightBoundary = boundaryRect
    ? boundaryRect.right - boundaryPadding
    : window.innerWidth - viewportPadding;

  if (taskRect) {
    const belowOffset = Math.max(gap, Math.round(taskRect.bottom - anchorRect.top) + gap);
    const aboveOffset = Math.max(gap, Math.round(anchorRect.bottom - taskRect.top) + gap);
    anchorElement.style.setProperty("--task-menu-below-offset", `${belowOffset}px`);
    anchorElement.style.setProperty("--task-menu-above-offset", `${aboveOffset}px`);
  } else {
    anchorElement.style.removeProperty("--task-menu-below-offset");
    anchorElement.style.removeProperty("--task-menu-above-offset");
  }

  const spaceBelow = bottomBoundary - anchorRect.bottom;
  const spaceAbove = anchorRect.top - topBoundary;

  if (spaceBelow < menuHeight + gap && spaceAbove > spaceBelow) {
    anchorElement.classList.add("open-upwards");
  }

  const maxMenuSpace = anchorElement.classList.contains("open-upwards")
    ? Math.max(140, spaceAbove)
    : Math.max(140, spaceBelow);

  const shouldClampMenu = menuHeight > (maxMenuSpace - 1);
  if (shouldClampMenu) {
    menuElement.style.maxHeight = `${maxMenuSpace}px`;
    menuElement.style.overflowY = "auto";
  } else {
    menuElement.style.maxHeight = "none";
    menuElement.style.overflowY = "visible";
  }

  sidePanels.forEach((panel) => {
    const panelMaxSpace = Math.max(160, maxMenuSpace);
    const panelNaturalHeight = panel.scrollHeight || panel.offsetHeight || 0;
    const shouldClampPanel = panelNaturalHeight > (panelMaxSpace - 1);

    if (shouldClampPanel) {
      panel.style.maxHeight = `${panelMaxSpace}px`;
      panel.style.overflowY = "auto";
    } else {
      panel.style.maxHeight = "none";
      panel.style.overflowY = "visible";
    }
  });

  if (isMobileViewport()) {
    sidePanels.forEach((panel) => {
      const panelHeight = panel.offsetHeight || 0;
      const preferBelowTop = anchorRect.bottom + 12;
      const preferAboveTop = anchorRect.top - panelHeight - 12;
      let top = preferBelowTop;

      if (top + panelHeight > bottomBoundary && preferAboveTop >= topBoundary) {
        top = preferAboveTop;
      }

      top = Math.min(
        Math.max(topBoundary, top),
        Math.max(topBoundary, bottomBoundary - panelHeight)
      );

      panel.style.top = `${Math.round(top)}px`;
    });

    return;
  }

  const spaceRight = rightBoundary - anchorRect.right;
  const spaceLeft = anchorRect.left - leftBoundary;
  const widestPanel = 228 + 206 + 14;
  if (spaceRight < widestPanel && spaceLeft > spaceRight + 18) {
    anchorElement.classList.add("side-open-left");
  }
}

function toggleTaskActionMenu(taskElement, anchorElement) {
  const isSameMenu =
    activeTaskActionMenu &&
    activeTaskActionMenu.anchorElement === anchorElement;

  closeTaskActionMenu();

  if (isSameMenu) return;

  const isDayOverlayContext = !!taskElement.closest("#dayOverlay.day-overlay-cardless");

  const overlay = document.createElement("div");
  overlay.id = "taskActionOverlay";
  document.body.appendChild(overlay);

  const hostColumn = taskElement.closest(".col");
  hostColumn?.classList.add("task-focus-host");
  anchorElement.classList.add("open");
  taskElement.classList.add("menu-open");
  document.body.classList.add("task-action-focus");
  const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  const scrollBlock = isDayOverlayContext ? "start" : "center";
  taskElement?.scrollIntoView({
    block: scrollBlock,
    inline: "nearest",
    behavior: prefersReducedMotion ? "auto" : "smooth"
  });
  positionTaskActionMenu(anchorElement);
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      positionTaskActionMenu(anchorElement);
    });
  });
  if (!prefersReducedMotion) {
    setTimeout(() => positionTaskActionMenu(anchorElement), 320);
  }
  activeTaskActionMenu = {
    taskElement,
    anchorElement,
    hostColumn,
    overlayElement: overlay
  };
}

function getStablePreviewPosition(targetIndex, percent, draggedIndex, isSameContainer) {
  const existingTarget = mobileActiveDropTarget;
  const existingIndex = existingTarget?.insertIndex;

  if (isSameContainer && targetIndex === draggedIndex + 1) {
    if (percent < MOBILE_DRAG_PREVIEW_STICKY_TOP) return null;
    return "after";
  }

  if (isSameContainer && targetIndex === draggedIndex - 1) {
    if (percent > MOBILE_DRAG_PREVIEW_STICKY_BOTTOM) return null;
    return "before";
  }

  if (percent <= MOBILE_DRAG_PREVIEW_STICKY_TOP) return "before";
  if (percent >= MOBILE_DRAG_PREVIEW_STICKY_BOTTOM) return "after";

  if (existingTarget?.taskIndex === targetIndex && existingTarget?.sameContainer === isSameContainer) {
    if (existingIndex === targetIndex) return "before";
    if (existingIndex === targetIndex + 1) return "after";
  }

  return percent < 0.5 ? "before" : "after";
}

function isMobileViewport() {
  return window.innerWidth <= MOBILE_BREAKPOINT;
}

function isMobileTaskFocusEnabled() {
  return isTouchDevice && isMobileViewport();
}

function forceMobileRenderRefresh(renderFn) {
  if (!isMobileViewport()) return;
  requestAnimationFrame(() => {
    if (currentViewMode === "tasks") {
      init();
      return;
    }
    renderFn?.();
    renderMiniCalendar();
  });
}

function captureMobileScrollSnapshot() {
  if (!isMobileViewport()) return;
  const host = document.querySelector(".board-scroll");
  if (!host) return;
  mobileFocusScrollSnapshot = {
    host,
    top: host.scrollTop,
    left: host.scrollLeft
  };
}

function restoreMobileScrollSnapshot() {
  if (!mobileFocusScrollSnapshot) return;
  const { host, top, left } = mobileFocusScrollSnapshot;
  if (host) {
    host.scrollTop = top;
    host.scrollLeft = left;
  }
  mobileFocusScrollSnapshot = null;
}

function clearTaskMobileFocus() {
  if (activeTaskMobileFocus) {
    const { taskElement, menuElement, overlayElement, cloneElement } = activeTaskMobileFocus;

    taskElement?.classList.remove("task-mobile-focus");
    taskElement?.classList.remove("task-mobile-focus-source");
    menuElement?.remove();
    overlayElement?.remove();
    cloneElement?.remove();

    activeTaskMobileFocus = null;
  }

  // Defensive cleanup: ensure no lingering focus classes remain on tasks.
  document.querySelectorAll(".task.task-mobile-focus, .task.task-mobile-focus-source").forEach((el) => {
    el.classList.remove("task-mobile-focus");
    el.classList.remove("task-mobile-focus-source");
  });
}

function resetTransientOverlays() {
  closeTaskActionMenu();
  clearTaskMobileFocus();
  closeStudyRoomActionConfirmOverlay();
  closeStudyRoomClosureSummaryOverlay();
  document.getElementById("taskActionOverlay")?.remove();
  document.getElementById("taskMobileOverlay")?.remove();
  document.body.classList.remove("task-action-focus");
}

function getChangelogSeenStorageKey(uid = currentUser?.uid){
  return `${CHANGELOG_MODAL_LOCAL_STORAGE_PREFIX}${uid || "guest"}`;
}

function getStoredSeenChangelogVersion(uid = currentUser?.uid){
  try {
    return String(localStorage.getItem(getChangelogSeenStorageKey(uid)) || "").trim();
  } catch {
    return "";
  }
}

function setStoredSeenChangelogVersion(version, uid = currentUser?.uid){
  const storageKey = getChangelogSeenStorageKey(uid);
  const safeVersion = String(version || "").trim();
  try {
    if (!safeVersion) {
      localStorage.removeItem(storageKey);
      return;
    }
    localStorage.setItem(storageKey, safeVersion);
  } catch (error) {
    console.warn("No se pudo guardar localmente la versión de changelog vista.", error);
  }
}

function getGuidedTutorialCompletionStorageKey(uid = currentUser?.uid){
  return `${GUIDED_TUTORIAL_COMPLETED_LOCAL_STORAGE_PREFIX}${uid || "guest"}`;
}

function getStoredGuidedTutorialCompleted(uid = currentUser?.uid){
  try {
    return localStorage.getItem(getGuidedTutorialCompletionStorageKey(uid)) === "1";
  } catch {
    return false;
  }
}

function setStoredGuidedTutorialCompleted(completed, uid = currentUser?.uid){
  const storageKey = getGuidedTutorialCompletionStorageKey(uid);
  const safeCompleted = Boolean(completed);
  try {
    if (!safeCompleted) {
      localStorage.removeItem(storageKey);
      return;
    }
    localStorage.setItem(storageKey, "1");
  } catch (error) {
    console.warn("No se pudo guardar localmente el estado del tutorial inicial.", error);
  }
}

function syncGuidedTutorialCompletionFromUserData(userData = {}){
  const cloudCompleted = Boolean(userData?.[GUIDED_TUTORIAL_COMPLETED_FIREBASE_FIELD]);
  if (cloudCompleted && currentUser?.uid) {
    setStoredGuidedTutorialCompleted(true, currentUser.uid);
  }

  const localCompleted = getStoredGuidedTutorialCompleted(currentUser?.uid);
  guidedTutorialCompletedForCurrentUser = cloudCompleted || localCompleted;

  if (!cloudCompleted && localCompleted && currentUser?.uid) {
    void markGuidedTutorialAsCompletedForCurrentUser({ forceCloudSync: true });
  }

  return guidedTutorialCompletedForCurrentUser;
}

function resetGuidedTutorialAutostartState(){
  guidedTutorialCompletedForCurrentUser = false;
  guidedTutorialAutoStartQueued = false;
  guidedTutorialAutoStartInFlight = false;
  guidedTutorialCompletionPersistPromise = null;
}

function isChangelogUpdateModalOpen(){
  return Boolean(document.getElementById("changelogUpdateOverlay"));
}

function queueGuidedTutorialAutostartIfNeeded(userData = {}){
  if (!currentUser?.uid) return;

  const alreadyCompleted = syncGuidedTutorialCompletionFromUserData(userData);
  if (alreadyCompleted) {
    if (isPlayerReadyForAchievementChecks()) {
      checkAchievements({ silent: false });
    }
    maybeFlushAchievementUnlockQueue();
    guidedTutorialAutoStartQueued = false;
    return;
  }

  guidedTutorialAutoStartQueued = true;
  void maybeRunGuidedTutorialAutostart();
}

async function maybeRunGuidedTutorialAutostart(){
  if (!guidedTutorialAutoStartQueued) return;
  if (guidedTutorialAutoStartInFlight) return;
  if (!currentUser?.uid) return;
  if (guidedTutorialState.active) return;
  if (guidedTutorialCompletedForCurrentUser) {
    guidedTutorialAutoStartQueued = false;
    return;
  }
  if (isChangelogUpdateModalOpen()) return;

  guidedTutorialAutoStartQueued = false;
  guidedTutorialAutoStartInFlight = true;

  try {
    await startGuidedTutorial({ persistCompletion: true });
  } catch (error) {
    console.error("No se pudo iniciar automáticamente el tutorial inicial.", error);
    guidedTutorialAutoStartQueued = true;
  } finally {
    guidedTutorialAutoStartInFlight = false;
  }
}

async function markGuidedTutorialAsCompletedForCurrentUser({ forceCloudSync = false } = {}){
  if (!currentUser?.uid) return;
  if (guidedTutorialCompletedForCurrentUser && !forceCloudSync) return;

  guidedTutorialCompletedForCurrentUser = true;
  guidedTutorialAutoStartQueued = false;
  setStoredGuidedTutorialCompleted(true, currentUser.uid);
  if (isPlayerReadyForAchievementChecks()) {
    checkAchievements({ silent: forceCloudSync });
  }
  maybeFlushAchievementUnlockQueue();

  if (guidedTutorialCompletionPersistPromise) {
    return guidedTutorialCompletionPersistPromise;
  }

  guidedTutorialCompletionPersistPromise = setDoc(
    doc(db, "users", currentUser.uid),
    {
      [GUIDED_TUTORIAL_COMPLETED_FIREBASE_FIELD]: true,
      [GUIDED_TUTORIAL_COMPLETED_AT_FIREBASE_FIELD]: Date.now()
    },
    { merge: true }
  )
    .catch((error) => {
      console.warn("No se pudo guardar en Firebase la finalización del tutorial inicial.", error);
    })
    .finally(() => {
      guidedTutorialCompletionPersistPromise = null;
    });

  return guidedTutorialCompletionPersistPromise;
}

