async function findUserDocumentByEmail(email){
  const rawEmail = String(email || "").trim();
  const normalizedEmail = rawEmail.toLowerCase();
  if (!normalizedEmail) return null;

  const lookups = [
    query(collection(db, "users"), where("emailLower", "==", normalizedEmail), limit(1)),
    query(collection(db, "users"), where("email", "==", rawEmail), limit(1))
  ];

  if (rawEmail !== normalizedEmail) {
    lookups.push(
      query(collection(db, "users"), where("email", "==", normalizedEmail), limit(1))
    );
  }

  for (const lookup of lookups) {
    const snapshot = await getDocs(lookup);
    if (!snapshot.empty) {
      const userSnap = snapshot.docs[0];
      return {
        uid: userSnap.id,
        data: userSnap.data() || {},
        ref: userSnap.ref
      };
    }
  }

  return null;
}

function isFirestorePermissionError(err){
  const code = String(err?.code || "");
  const message = String(err?.message || "").toLowerCase();
  return code.includes("permission-denied") || message.includes("insufficient permissions");
}

function isFirestoreNotFoundError(err){
  const code = String(err?.code || "");
  const message = String(err?.message || "").toLowerCase();
  return (
    code.includes("not-found") ||
    message.includes("no document to update") ||
    message.includes("no document to delete")
  );
}

function isStudyRoomCloseResolvedStatus(status = ""){
  const safeStatus = String(status || "").trim();
  return (
    safeStatus === "success" ||
    safeStatus === "soft-success" ||
    safeStatus === "notfound" ||
    safeStatus === "skipped"
  );
}

async function forceClosePrimaryStudyRoomDoc(
  roomId = "",
  {
    now = Date.now(),
    closedByUid = "",
    closedByName = ""
  } = {}
){
  const safeRoomId = String(roomId || "").trim();
  if (!safeRoomId) return "skipped";

  const safeClosedByUid = String(closedByUid || "").trim();
  const safeClosedByName = String(closedByName || "Admin").trim() || "Admin";

  try {
    await deleteDoc(doc(db, STUDY_ROOMS_COLLECTION, safeRoomId));
    return "success";
  } catch (err) {
    if (isFirestoreNotFoundError(err)) {
      return "notfound";
    }
    if (!isFirestorePermissionError(err)) {
      console.warn("No se pudo eliminar sala principal durante cierre forzado.", err);
      return "error";
    }
  }

  try {
    await updateDoc(doc(db, STUDY_ROOMS_COLLECTION, safeRoomId), {
      isActive: false,
      updatedAt: Math.max(0, Number(now) || Date.now()),
      closedAt: Math.max(0, Number(now) || Date.now()),
      closedByUid: safeClosedByUid,
      closedByName: safeClosedByName,
      participants: deleteField(),
      participantsCount: 0,
      boards: deleteField(),
      chat: deleteField(),
      invited: deleteField(),
      allowed: deleteField(),
      music: deleteField()
    });
    return "soft-success";
  } catch (err) {
    if (isFirestoreNotFoundError(err)) {
      return "notfound";
    }
    if (isFirestorePermissionError(err)) {
      return "permission";
    }
    console.warn("No se pudo cerrar sala principal con fallback de update.", err);
    return "error";
  }
}

