function getStudyRoomInviteAccessStorageKey(uid = ""){
  const safeUid = String(uid || currentUser?.uid || "").trim();
  if (!safeUid) return "";
  return `${STUDY_ROOM_INVITE_ACCESS_STORAGE_PREFIX}${safeUid}`;
}

function normalizeStudyRoomInviteAccessEntry(entry = {}, fallbackRoomId = ""){
  const source = entry && typeof entry === "object" && !Array.isArray(entry)
    ? entry
    : {};
  const roomId = String(source.roomId || fallbackRoomId || "").trim();
  if (!roomId) return null;

  const grantedAt = Math.max(
    0,
    Number(source.grantedAt || source.updatedAt || source.acceptedAt) || 0
  );
  if (!grantedAt) return null;

  return {
    roomId,
    invitedByUid: String(source.invitedByUid || source.inviterUid || "").trim(),
    roomTitle: String(source.roomTitle || source.title || "Sala de estudio").trim() || "Sala de estudio",
    roomAccessSource: normalizeStudyRoomInviteAccessSource(
      source.roomAccessSource ||
      source.roomSource ||
      ""
    ),
    grantedAt
  };
}

function readStoredStudyRoomInviteAccessMap(uid = ""){
  const key = getStudyRoomInviteAccessStorageKey(uid);
  if (!key) return new Map();

  let raw = "";
  try {
    raw = String(localStorage.getItem(key) || "").trim();
  } catch {
    return new Map();
  }
  if (!raw) return new Map();

  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch {
    return new Map();
  }

  const candidates = [];
  if (Array.isArray(parsed)) {
    parsed.forEach((entry) => candidates.push(entry));
  } else if (parsed && typeof parsed === "object") {
    Object.entries(parsed).forEach(([roomId, entry]) => {
      if (entry && typeof entry === "object" && !Array.isArray(entry)) {
        candidates.push({
          ...entry,
          roomId: String(entry.roomId || roomId || "").trim()
        });
      } else {
        candidates.push({
          roomId: String(roomId || "").trim(),
          grantedAt: 0
        });
      }
    });
  } else {
    return new Map();
  }

  const now = Date.now();
  const map = new Map();
  candidates.forEach((entry) => {
    const normalizedEntry = normalizeStudyRoomInviteAccessEntry(entry, entry?.roomId);
    if (!normalizedEntry) return;
    if ((now - normalizedEntry.grantedAt) > STUDY_ROOM_INVITE_ACCESS_MAX_AGE_MS) return;
    const previous = map.get(normalizedEntry.roomId);
    if (!previous || normalizedEntry.grantedAt >= Number(previous.grantedAt || 0)) {
      map.set(normalizedEntry.roomId, normalizedEntry);
    }
  });

  if (map.size <= STUDY_ROOM_INVITE_ACCESS_MAX_ENTRIES) {
    return map;
  }

  const trimmed = Array.from(map.values())
    .sort((a, b) => (Number(b.grantedAt) || 0) - (Number(a.grantedAt) || 0))
    .slice(0, STUDY_ROOM_INVITE_ACCESS_MAX_ENTRIES);
  return new Map(trimmed.map((entry) => [entry.roomId, entry]));
}

function persistStoredStudyRoomInviteAccessMap(accessByRoomId = new Map(), uid = ""){
  const key = getStudyRoomInviteAccessStorageKey(uid);
  if (!key) return;

  const safeMap = accessByRoomId instanceof Map
    ? accessByRoomId
    : new Map();
  const now = Date.now();
  const normalizedEntries = Array.from(safeMap.values())
    .map((entry) => normalizeStudyRoomInviteAccessEntry(entry, entry?.roomId))
    .filter((entry) => {
      if (!entry) return false;
      return (now - entry.grantedAt) <= STUDY_ROOM_INVITE_ACCESS_MAX_AGE_MS;
    })
    .sort((a, b) => (Number(b.grantedAt) || 0) - (Number(a.grantedAt) || 0))
    .slice(0, STUDY_ROOM_INVITE_ACCESS_MAX_ENTRIES);

  try {
    if (!normalizedEntries.length) {
      localStorage.removeItem(key);
      return;
    }
    localStorage.setItem(key, JSON.stringify(normalizedEntries));
  } catch {}
}

function ensureStudyRoomInviteAccessHydrated(uid = ""){
  const safeUid = String(uid || currentUser?.uid || "").trim();
  if (!safeUid) {
    studyRoomsState.inviteAccessByRoomId = new Map();
    studyRoomsState.inviteAccessLoadedUid = "";
    return studyRoomsState.inviteAccessByRoomId;
  }

  if (
    studyRoomsState.inviteAccessLoadedUid === safeUid &&
    studyRoomsState.inviteAccessByRoomId instanceof Map
  ) {
    return studyRoomsState.inviteAccessByRoomId;
  }

  const loaded = readStoredStudyRoomInviteAccessMap(safeUid);
  studyRoomsState.inviteAccessByRoomId = loaded;
  studyRoomsState.inviteAccessLoadedUid = safeUid;
  persistStoredStudyRoomInviteAccessMap(loaded, safeUid);
  return loaded;
}

function hasCurrentUserAcceptedStudyRoomInviteAccess(roomData = null, roomId = ""){
  const ownUid = String(currentUser?.uid || "").trim();
  if (!ownUid) return false;

  const accessByRoomId = ensureStudyRoomInviteAccessHydrated(ownUid);
  if (!(accessByRoomId instanceof Map) || !accessByRoomId.size) return false;

  const safeRoomId = String(roomData?.id || roomId || "").trim();
  const safeCreatedByUid = String(roomData?.createdByUid || "").trim();
  if (!safeRoomId && !safeCreatedByUid) return false;

  const localAccessEntry = accessByRoomId.get(safeRoomId) || (
    safeCreatedByUid
      ? accessByRoomId.get(safeCreatedByUid)
      : null
  );
  if (!localAccessEntry || typeof localAccessEntry !== "object") return false;

  const safeInvitedByUid = String(localAccessEntry.invitedByUid || "").trim();
  if (safeCreatedByUid && safeInvitedByUid && safeInvitedByUid !== safeCreatedByUid) {
    return false;
  }

  return true;
}

function getCurrentUserAcceptedStudyRoomInviteAccessEntry(roomId = "", ownerUid = ""){
  const ownUid = String(currentUser?.uid || "").trim();
  const safeRoomId = String(roomId || "").trim();
  const safeOwnerUid = String(ownerUid || "").trim();
  if (!ownUid || (!safeRoomId && !safeOwnerUid)) return null;

  const accessByRoomId = ensureStudyRoomInviteAccessHydrated(ownUid);
  if (!(accessByRoomId instanceof Map)) return null;
  const entry = accessByRoomId.get(safeRoomId) || (
    safeOwnerUid
      ? accessByRoomId.get(safeOwnerUid)
      : null
  );
  if (!entry || typeof entry !== "object") return null;

  const normalized = normalizeStudyRoomInviteAccessEntry(
    entry,
    safeRoomId || safeOwnerUid
  );
  if (!normalized) return null;
  if ((Date.now() - normalized.grantedAt) > STUDY_ROOM_INVITE_ACCESS_MAX_AGE_MS) {
    if (safeRoomId) {
      accessByRoomId.delete(safeRoomId);
    }
    if (safeOwnerUid) {
      accessByRoomId.delete(safeOwnerUid);
    }
    persistStoredStudyRoomInviteAccessMap(accessByRoomId, ownUid);
    return null;
  }

  return normalized;
}

function grantCurrentUserStudyRoomInviteAccess(
  roomId,
  {
    invitedByUid = "",
    roomTitle = "",
    roomAccessSource = ""
  } = {}
){
  const ownUid = String(currentUser?.uid || "").trim();
  const safeRoomId = String(roomId || "").trim();
  if (!ownUid || !safeRoomId) return false;

  const accessByRoomId = ensureStudyRoomInviteAccessHydrated(ownUid);
  if (!(accessByRoomId instanceof Map)) {
    studyRoomsState.inviteAccessByRoomId = new Map();
  }
  const targetMap = studyRoomsState.inviteAccessByRoomId instanceof Map
    ? studyRoomsState.inviteAccessByRoomId
    : new Map();
  const previous = targetMap.get(safeRoomId);
  const safeInvitedByUid = String(invitedByUid || previous?.invitedByUid || "").trim();
  const safeRoomTitle = String(roomTitle || previous?.roomTitle || "Sala de estudio").trim() || "Sala de estudio";
  const safeRoomAccessSource = normalizeStudyRoomInviteAccessSource(
    roomAccessSource ||
    previous?.roomAccessSource ||
    ""
  );
  const now = Date.now();

  targetMap.set(safeRoomId, {
    roomId: safeRoomId,
    invitedByUid: safeInvitedByUid,
    roomTitle: safeRoomTitle,
    roomAccessSource: safeRoomAccessSource,
    grantedAt: now
  });
  if (safeInvitedByUid && safeInvitedByUid !== safeRoomId) {
    const ownerPrevious = targetMap.get(safeInvitedByUid);
    targetMap.set(safeInvitedByUid, {
      roomId: safeInvitedByUid,
      invitedByUid: safeInvitedByUid,
      roomTitle: safeRoomTitle || ownerPrevious?.roomTitle || "Sala de estudio",
      roomAccessSource: safeRoomAccessSource || ownerPrevious?.roomAccessSource || "",
      grantedAt: now
    });
  }

  studyRoomsState.inviteAccessByRoomId = targetMap;
  studyRoomsState.inviteAccessLoadedUid = ownUid;
  persistStoredStudyRoomInviteAccessMap(targetMap, ownUid);
  return true;
}

function revokeCurrentUserStudyRoomInviteAccess(roomId = "", ownerUid = ""){
  const ownUid = String(currentUser?.uid || "").trim();
  const safeRoomId = String(roomId || "").trim();
  const safeOwnerUid = String(ownerUid || "").trim();
  if (!ownUid || (!safeRoomId && !safeOwnerUid)) return false;

  const accessByRoomId = ensureStudyRoomInviteAccessHydrated(ownUid);
  if (!(accessByRoomId instanceof Map) || !accessByRoomId.size) return false;

  let changed = false;
  const maybeDeleteKey = (key) => {
    const safeKey = String(key || "").trim();
    if (!safeKey) return;
    if (accessByRoomId.delete(safeKey)) {
      changed = true;
    }
  };

  maybeDeleteKey(safeRoomId);
  maybeDeleteKey(safeOwnerUid);

  Array.from(accessByRoomId.entries()).forEach(([entryKey, entryValue]) => {
    const normalizedEntry = normalizeStudyRoomInviteAccessEntry(entryValue, entryKey);
    if (!normalizedEntry) return;

    const entryRoomId = String(normalizedEntry.roomId || "").trim();
    const entryOwnerUid = String(normalizedEntry.invitedByUid || "").trim();
    const matchesRoom = !!safeRoomId && (
      entryRoomId === safeRoomId ||
      String(entryKey || "").trim() === safeRoomId
    );
    const matchesOwner = !!safeOwnerUid && (
      entryOwnerUid === safeOwnerUid ||
      String(entryKey || "").trim() === safeOwnerUid
    );
    if (!matchesRoom && !matchesOwner) return;

    if (accessByRoomId.delete(entryKey)) {
      changed = true;
    }
  });

  if (!changed) return false;

  studyRoomsState.inviteAccessByRoomId = accessByRoomId;
  studyRoomsState.inviteAccessLoadedUid = ownUid;
  persistStoredStudyRoomInviteAccessMap(accessByRoomId, ownUid);
  return true;
}

function readStoredStudyRoomActiveSession(uid = ""){
  const key = getStudyRoomActiveSessionStorageKey(uid);
  if (!key) return "";

  try {
    const roomId = String(localStorage.getItem(key) || "").trim();
    return roomId;
  } catch {
    return "";
  }
}

function persistStudyRoomActiveSession(roomId = "", uid = ""){
  const key = getStudyRoomActiveSessionStorageKey(uid);
  if (!key) return;

  const safeRoomId = String(roomId || "").trim();
  try {
    if (!safeRoomId) {
      localStorage.removeItem(key);
      return;
    }
    localStorage.setItem(key, safeRoomId);
  } catch {}
}

function clearStoredStudyRoomActiveSession(uid = ""){
  persistStudyRoomActiveSession("", uid);
}

function getStudyRoomClosureSummarySeenStorageKey(uid = ""){
  const safeUid = String(uid || currentUser?.uid || "").trim();
  if (!safeUid) return "";
  return `${STUDY_ROOM_CLOSURE_SUMMARY_SEEN_STORAGE_PREFIX}${safeUid}`;
}

function readStoredStudyRoomClosureSummarySeenId(uid = ""){
  const key = getStudyRoomClosureSummarySeenStorageKey(uid);
  if (!key) return "";

  try {
    return String(localStorage.getItem(key) || "").trim();
  } catch {
    return "";
  }
}

function persistStudyRoomClosureSummarySeenId(summaryId = "", uid = ""){
  const key = getStudyRoomClosureSummarySeenStorageKey(uid);
  if (!key) return;
  const safeSummaryId = String(summaryId || "").trim();

  try {
    if (!safeSummaryId) {
      localStorage.removeItem(key);
      return;
    }
    localStorage.setItem(key, safeSummaryId);
  } catch {}
}

async function restoreStudyRoomActiveSessionFromStorage(){
  const ownUid = String(currentUser?.uid || "").trim();
  if (!ownUid) return false;

  const currentActiveRoomId = String(studyRoomsState.activeRoomId || "").trim();
  if (currentActiveRoomId) return true;

  const storedRoomId = readStoredStudyRoomActiveSession(ownUid);
  if (!storedRoomId) return false;

  const opened = await openStudyRoomSession(storedRoomId);
  if (!opened) {
    clearStoredStudyRoomActiveSession(ownUid);
  }
  return opened;
}

function normalizeTextForSearch(value = ""){
  const raw = String(value ?? "");
  const lowered = raw.toLowerCase().trim();
  if (typeof lowered.normalize !== "function") {
    return lowered;
  }

  return lowered.normalize("NFD").replace(/[\u0300-\u036f]/g, "");
}

function normalizeSocialUser(entry = {}, fallbackUid = ""){
  const uid = String(entry?.uid || fallbackUid || "").trim();
  if (!uid) return null;

  const email = String(entry?.email || "").trim();
  const name = String(entry?.name || entry?.displayName || "Usuario").trim() || "Usuario";
  const photo = String(entry?.photo || "").trim();
  const requestedAt = Math.max(0, Number(entry?.requestedAt) || 0);
  const addedAt = Math.max(0, Number(entry?.addedAt) || 0);

  return {
    uid,
    name,
    nameLower: name.toLowerCase(),
    nameSearch: normalizeTextForSearch(name),
    email,
    emailLower: email.toLowerCase(),
    photo,
    requestedAt,
    addedAt
  };
}

function parseSocialUserMap(rawMap = {}){
  if (!rawMap || typeof rawMap !== "object" || Array.isArray(rawMap)) {
    return [];
  }

  const entries = [];

  Object.entries(rawMap).forEach(([uid, value]) => {
    if (!value || typeof value !== "object") return;
    const normalized = normalizeSocialUser(value, uid);
    if (!normalized) return;
    entries.push(normalized);
  });

  return entries;
}

function parseSocialTimestampMap(rawMap = {}){
  if (!rawMap || typeof rawMap !== "object" || Array.isArray(rawMap)) {
    return new Map();
  }

  const parsed = new Map();

  Object.entries(rawMap).forEach(([uid, value]) => {
    const safeUid = String(uid || "").trim();
    if (!safeUid) return;

    const timestamp = Math.max(0, Number(value) || 0);
    if (!timestamp) return;
    parsed.set(safeUid, timestamp);
  });

  return parsed;
}

function parseSocialOutgoingMap(rawMap = {}){
  if (!rawMap || typeof rawMap !== "object" || Array.isArray(rawMap)) {
    return [];
  }

  const entries = [];

  Object.entries(rawMap).forEach(([uid, value]) => {
    const safeUid = String(uid || "").trim();
    if (!safeUid || !value || typeof value !== "object") return;

    const normalized = normalizeSocialUser(
      {
        uid: safeUid,
        name: value.name || "Usuario",
        photo: value.photo || "",
        requestedAt: value.requestedAt
      },
      safeUid
    );

    if (!normalized) return;

    entries.push({
      ...normalized,
      status: String(value.status || "pending").trim().toLowerCase() || "pending"
    });
  });

  return entries;
}

function parseSocialChatReadsMap(rawMap = {}){
  if (!rawMap || typeof rawMap !== "object" || Array.isArray(rawMap)) {
    return new Map();
  }

  const parsed = new Map();

  Object.entries(rawMap).forEach(([uid, value]) => {
    const safeUid = String(uid || "").trim();
    if (!safeUid) return;

    let timestamp = 0;
    if (typeof value === "number") {
      timestamp = Math.max(0, Number(value) || 0);
    } else if (value && typeof value === "object") {
      timestamp = Math.max(0, Number(value.lastReadAt) || 0);
    }

    if (!timestamp) return;
    parsed.set(safeUid, timestamp);
  });

  return parsed;
}

function getSocialReadTimestampFromDoc(data = {}, peerUid = ""){
  const safePeerUid = String(peerUid || "").trim();
  if (!safePeerUid || !data || typeof data !== "object") return 0;

  const readMap = data?.[SOCIAL_CHAT_READS_FIELD];
  if (!readMap || typeof readMap !== "object" || Array.isArray(readMap)) {
    return 0;
  }

  const entry = readMap[safePeerUid];
  if (typeof entry === "number") {
    return Math.max(0, Number(entry) || 0);
  }

  if (!entry || typeof entry !== "object") {
    return 0;
  }

  return Math.max(0, Number(entry.lastReadAt) || 0);
}

function countUnreadSocialMessagesFromFriendDoc(friendUid, friendDocData = {}, ownUid = "", readAt = 0){
  const safeFriendUid = String(friendUid || "").trim();
  const safeOwnUid = String(ownUid || "").trim();
  if (!safeFriendUid || !safeOwnUid) return 0;

  const thread = parseSocialChatThread(
    getSocialChatThreadFromDoc(friendDocData, safeOwnUid),
    { fromUid: safeFriendUid, toUid: safeOwnUid }
  );

  const safeReadAt = Math.max(0, Number(readAt) || 0);
  return thread.reduce((count, message) => {
    const fromUid = String(message?.fromUid || "").trim();
    const createdAt = Math.max(0, Number(message?.createdAt) || 0);
    if (fromUid !== safeFriendUid) return count;
    return createdAt > safeReadAt ? count + 1 : count;
  }, 0);
}

function getSocialChatThreadFromDoc(data = {}, peerUid = ""){
  const safePeerUid = String(peerUid || "").trim();
  if (!safePeerUid || !data || typeof data !== "object") return {};

  const outbox = data?.[SOCIAL_CHAT_OUTBOX_FIELD];
  if (!outbox || typeof outbox !== "object" || Array.isArray(outbox)) {
    return {};
  }

  const thread = outbox[safePeerUid];
  if (!thread || typeof thread !== "object" || Array.isArray(thread)) {
    return {};
  }

  return thread;
}

function normalizeSocialChatMessageKind(rawKind = ""){
  const safeKind = String(rawKind || "").trim().toLowerCase();
  if (safeKind === SOCIAL_CHAT_KIND_STUDY_ROOM_INVITE) {
    return SOCIAL_CHAT_KIND_STUDY_ROOM_INVITE;
  }
  return SOCIAL_CHAT_KIND_MESSAGE;
}

function normalizeSocialChatStudyRoomInviteStatus(rawStatus = ""){
  const safeStatus = String(rawStatus || "").trim().toLowerCase();
  if (safeStatus === SOCIAL_CHAT_STUDY_ROOM_INVITE_STATUS_ACCEPTED) {
    return SOCIAL_CHAT_STUDY_ROOM_INVITE_STATUS_ACCEPTED;
  }
  if (safeStatus === SOCIAL_CHAT_STUDY_ROOM_INVITE_STATUS_REJECTED) {
    return SOCIAL_CHAT_STUDY_ROOM_INVITE_STATUS_REJECTED;
  }
  if (safeStatus === SOCIAL_CHAT_STUDY_ROOM_INVITE_STATUS_ROOM_CLOSED) {
    return SOCIAL_CHAT_STUDY_ROOM_INVITE_STATUS_ROOM_CLOSED;
  }
  return SOCIAL_CHAT_STUDY_ROOM_INVITE_STATUS_PENDING;
}

function normalizeStudyRoomInviteAccessSource(rawSource = ""){
  const safeSource = String(rawSource || "").trim().toLowerCase();
  if (safeSource === "owned") return "owned";
  if (safeSource === "primary") return "primary";
  return "";
}

function normalizeSocialChatStudyRoomInvitePayload(rawPayload = {}, defaults = {}){
  const source = rawPayload && typeof rawPayload === "object" && !Array.isArray(rawPayload)
    ? rawPayload
    : {};
  const fallback = defaults && typeof defaults === "object" && !Array.isArray(defaults)
    ? defaults
    : {};

  const roomId = String(
    source.roomId ||
    source.id ||
    fallback.roomId ||
    fallback.id ||
    ""
  ).trim();
  const roomTitle = String(
    source.roomTitle ||
    source.title ||
    fallback.roomTitle ||
    fallback.title ||
    "Sala de estudio"
  ).trim() || "Sala de estudio";
  const invitedByUid = String(
    source.invitedByUid ||
    source.inviterUid ||
    source.fromUid ||
    fallback.invitedByUid ||
    fallback.inviterUid ||
    ""
  ).trim();
  const invitedByName = String(
    source.invitedByName ||
    source.inviterName ||
    source.fromName ||
    fallback.invitedByName ||
    fallback.inviterName ||
    ""
  ).trim();
  const roomAccessSource = normalizeStudyRoomInviteAccessSource(
    source.roomAccessSource ||
    source.roomSource ||
    fallback.roomAccessSource ||
    fallback.roomSource ||
    ""
  );

  return {
    roomId,
    roomTitle,
    invitedByUid,
    invitedByName,
    roomAccessSource
  };
}

function normalizeSocialChatStudyRoomInviteResponse(entry = {}, fallback = {}){
  const source = entry && typeof entry === "object" && !Array.isArray(entry)
    ? entry
    : {};
  const fallbackEntry = fallback && typeof fallback === "object" && !Array.isArray(fallback)
    ? fallback
    : {};

  const statusSource = typeof entry === "string"
    ? entry
    : source.status;
  const status = normalizeSocialChatStudyRoomInviteStatus(statusSource);

  return {
    status,
    roomId: String(source.roomId || fallbackEntry.roomId || "").trim(),
    roomTitle: String(source.roomTitle || fallbackEntry.roomTitle || "").trim() || "Sala de estudio",
    invitedByUid: String(source.invitedByUid || fallbackEntry.invitedByUid || "").trim(),
    invitedByName: String(source.invitedByName || fallbackEntry.invitedByName || "").trim(),
    roomAccessSource: normalizeStudyRoomInviteAccessSource(
      source.roomAccessSource ||
      source.roomSource ||
      fallbackEntry.roomAccessSource ||
      fallbackEntry.roomSource ||
      ""
    ),
    updatedAt: Math.max(0, Number(source.updatedAt || source.respondedAt) || 0),
    respondedAt: Math.max(0, Number(source.respondedAt || source.updatedAt) || 0)
  };
}

function parseSocialChatStudyRoomInviteResponsesByMessageId(ownData = {}, friendUid = ""){
  const safeFriendUid = String(friendUid || "").trim();
  if (!safeFriendUid || !ownData || typeof ownData !== "object") {
    return new Map();
  }

  const rawStore = ownData?.[SOCIAL_CHAT_STUDY_ROOM_INVITES_FIELD];
  if (!rawStore || typeof rawStore !== "object" || Array.isArray(rawStore)) {
    return new Map();
  }

  const rawByFriend = rawStore[safeFriendUid];
  if (!rawByFriend || typeof rawByFriend !== "object" || Array.isArray(rawByFriend)) {
    return new Map();
  }

  const parsed = new Map();
  Object.entries(rawByFriend).forEach(([messageId, value]) => {
    const safeMessageId = String(messageId || "").trim();
    if (!safeMessageId) return;
    parsed.set(safeMessageId, normalizeSocialChatStudyRoomInviteResponse(value));
  });
  return parsed;
}

function isSocialChatStudyRoomInviteMessage(message = {}){
  return normalizeSocialChatMessageKind(message?.kind) === SOCIAL_CHAT_KIND_STUDY_ROOM_INVITE;
}

function parseSocialChatThread(rawThread = {}, defaults = {}){
  if (!rawThread || typeof rawThread !== "object" || Array.isArray(rawThread)) {
    return [];
  }

  const messages = [];

  Object.entries(rawThread).forEach(([fallbackId, value]) => {
    if (!value || typeof value !== "object") return;

    const id = String(value.id || fallbackId || "").trim();
    const text = String(value.text || "").trim();
    if (!id || !text) return;

    const fromUid = String(value.fromUid || defaults.fromUid || "").trim();
    const toUid = String(value.toUid || defaults.toUid || "").trim();
    const createdAt = Math.max(0, Number(value.createdAt) || 0);
    const kind = normalizeSocialChatMessageKind(value.kind || value.type);
    const studyRoomInvite = kind === SOCIAL_CHAT_KIND_STUDY_ROOM_INVITE
      ? normalizeSocialChatStudyRoomInvitePayload(value.studyRoomInvite, {
          roomId: value.roomId,
          roomTitle: value.roomTitle,
          invitedByUid: value.invitedByUid || fromUid,
          invitedByName: value.invitedByName,
          roomAccessSource: value.roomAccessSource || value.roomSource
        })
      : null;

    messages.push({
      id,
      fromUid,
      toUid,
      text: text.slice(0, SOCIAL_CHAT_MAX_LENGTH),
      createdAt,
      kind,
      studyRoomInvite
    });
  });

  messages.sort((a, b) => {
    const byTime = (Number(a.createdAt) || 0) - (Number(b.createdAt) || 0);
    if (byTime !== 0) return byTime;
    return String(a.id || "").localeCompare(String(b.id || ""), "es", { sensitivity: "base" });
  });

  return messages;
}

function buildSocialConversationMessages(friendUid, { ownData = {}, friendData = {} } = {}){
  const safeFriendUid = String(friendUid || "").trim();
  const ownUid = String(currentUser?.uid || "").trim();
  if (!safeFriendUid || !ownUid) return [];

  const ownThread = parseSocialChatThread(
    getSocialChatThreadFromDoc(ownData, safeFriendUid),
    { fromUid: ownUid, toUid: safeFriendUid }
  );
  const friendThread = parseSocialChatThread(
    getSocialChatThreadFromDoc(friendData, ownUid),
    { fromUid: safeFriendUid, toUid: ownUid }
  );
  const inviteResponsesByMessageId = parseSocialChatStudyRoomInviteResponsesByMessageId(
    ownData,
    safeFriendUid
  );

  const mergedByKey = new Map();
  [...ownThread, ...friendThread].forEach((message) => {
    const key = `${String(message.fromUid || "")}:${String(message.id || "")}`;
    if (!key) return;
    mergedByKey.set(key, message);
  });

  const orderedMessages = Array.from(mergedByKey.values()).sort((a, b) => {
    const byTime = (Number(a.createdAt) || 0) - (Number(b.createdAt) || 0);
    if (byTime !== 0) return byTime;
    return String(a.id || "").localeCompare(String(b.id || ""), "es", { sensitivity: "base" });
  });

  return orderedMessages.map((message) => {
    const safeMessage = message && typeof message === "object" ? message : {};
    const kind = normalizeSocialChatMessageKind(safeMessage.kind || safeMessage.type);
    if (kind !== SOCIAL_CHAT_KIND_STUDY_ROOM_INVITE) {
      return {
        ...safeMessage,
        kind: SOCIAL_CHAT_KIND_MESSAGE,
        studyRoomInvite: null,
        inviteResponseStatus: "",
        inviteResponseUpdatedAt: 0
      };
    }

    const normalizedInvitePayload = normalizeSocialChatStudyRoomInvitePayload(safeMessage.studyRoomInvite, {
      roomId: safeMessage.roomId,
      roomTitle: safeMessage.roomTitle,
      invitedByUid: safeMessage.invitedByUid || safeMessage.fromUid,
      invitedByName: safeMessage.invitedByName,
      roomAccessSource: safeMessage.roomAccessSource || safeMessage.roomSource
    });
    const isIncomingInvite = (
      String(safeMessage.fromUid || "").trim() === safeFriendUid &&
      String(safeMessage.toUid || "").trim() === ownUid
    );

    const responseEntry = isIncomingInvite
      ? inviteResponsesByMessageId.get(String(safeMessage.id || "").trim())
      : null;
    const inviteResponseStatus = isIncomingInvite
      ? normalizeSocialChatStudyRoomInviteStatus(responseEntry?.status)
      : "";
    const inviteResponseUpdatedAt = isIncomingInvite
      ? Math.max(0, Number(responseEntry?.updatedAt || responseEntry?.respondedAt) || 0)
      : 0;

    return {
      ...safeMessage,
      kind,
      studyRoomInvite: normalizedInvitePayload,
      inviteResponseStatus,
      inviteResponseUpdatedAt
    };
  });
}

function syncStudyRoomInviteAccessFromIncomingChatInvites(
  friendUid,
  {
    friendData = {}
  } = {}
){
  const safeFriendUid = String(friendUid || "").trim();
  const ownUid = String(currentUser?.uid || "").trim();
  if (!safeFriendUid || !ownUid) return 0;

  const incomingThread = parseSocialChatThread(
    getSocialChatThreadFromDoc(friendData, ownUid),
    { fromUid: safeFriendUid, toUid: ownUid }
  );
  if (!incomingThread.length) return 0;

  let grantsApplied = 0;
  incomingThread.forEach((message) => {
    if (!isSocialChatStudyRoomInviteMessage(message)) return;

    const invitePayload = normalizeSocialChatStudyRoomInvitePayload(message?.studyRoomInvite, {
      roomId: message?.roomId,
      roomTitle: message?.roomTitle,
      invitedByUid: message?.fromUid || safeFriendUid,
      invitedByName: message?.invitedByName,
      roomAccessSource: message?.roomAccessSource || message?.roomSource
    });
    const roomId = String(invitePayload.roomId || "").trim();
    const invitedByUid = String(invitePayload.invitedByUid || safeFriendUid).trim();
    const roomTitle = String(invitePayload.roomTitle || "Sala de estudio").trim() || "Sala de estudio";
    const roomAccessSource = String(invitePayload.roomAccessSource || "").trim();
    if (!roomId) return;

    const existingAccess = getCurrentUserAcceptedStudyRoomInviteAccessEntry(roomId, invitedByUid);
    const hasEquivalentAccess = !!(
      existingAccess &&
      String(existingAccess.invitedByUid || "").trim() === invitedByUid &&
      String(existingAccess.roomTitle || "Sala de estudio").trim() === roomTitle &&
      String(existingAccess.roomAccessSource || "").trim() === roomAccessSource
    );
    if (hasEquivalentAccess) return;

    const granted = grantCurrentUserStudyRoomInviteAccess(roomId, {
      invitedByUid,
      roomTitle,
      roomAccessSource
    });
    if (granted) {
      grantsApplied += 1;
    }
  });

  if (grantsApplied > 0) {
    logStudyRoomInviteDebug("WHT-01", "Whitelist local actualizada desde invitaciones entrantes de chat.", {
      friendUid: safeFriendUid,
      grantsApplied
    }, "ok");
  }

  return grantsApplied;
}

function normalizeStudyRoomSyncRoomUpdates(rawUpdates = {}){
  if (!rawUpdates || typeof rawUpdates !== "object" || Array.isArray(rawUpdates)) {
    return {};
  }

  const normalized = {};
  Object.entries(rawUpdates).forEach(([path, value]) => {
    const safePath = String(path || "").trim();
    if (!safePath) return;
    if (!/^[a-zA-Z0-9_.-]+$/.test(safePath)) return;
    if (safePath.startsWith(".") || safePath.endsWith(".") || safePath.includes("..")) return;
    normalized[safePath] = value;
  });
  return normalized;
}

function filterStudyRoomSyncRoomUpdatesForActor(roomUpdates = {}, actorUid = ""){
  const safeActorUid = String(actorUid || "").trim();
  const source = normalizeStudyRoomSyncRoomUpdates(roomUpdates);
  if (!Object.keys(source).length) return {};

  const filtered = {};
  Object.entries(source).forEach(([path, value]) => {
    const safePath = String(path || "").trim();
    if (!safePath) return;

    const isGlobalAllowedPath = (
      safePath === "updatedAt" ||
      safePath === "music" ||
      safePath.startsWith("chat.")
    );
    if (isGlobalAllowedPath) {
      filtered[safePath] = value;
      return;
    }
    if (!safeActorUid) return;

    if (
      safePath === `allowed.${safeActorUid}` ||
      safePath.startsWith(`allowed.${safeActorUid}.`) ||
      safePath === `invited.${safeActorUid}` ||
      safePath.startsWith(`invited.${safeActorUid}.`) ||
      safePath === `participants.${safeActorUid}` ||
      safePath.startsWith(`participants.${safeActorUid}.`) ||
      safePath === `boards.${safeActorUid}` ||
      safePath.startsWith(`boards.${safeActorUid}.`)
    ) {
      filtered[safePath] = value;
    }
  });

  return filtered;
}

function normalizeSocialStudyRoomSyncOp(entry = {}, fallbackId = "", friendUid = ""){
  const source = entry && typeof entry === "object" && !Array.isArray(entry)
    ? entry
    : {};

  const id = String(source.id || fallbackId || "").trim();
  const ownerUid = String(source.ownerUid || "").trim();
  const roomId = String(source.roomId || "").trim();
  const actorUid = String(source.actorUid || source.uid || "").trim();
  const createdAt = Math.max(0, Number(source.createdAt || source.updatedAt) || 0);
  const roomCreatedAt = Math.max(
    0,
    Number(source.roomCreatedAt || source.roomCreatedTimestamp || source.roomCreated || 0) || 0
  );
  const roomUpdates = normalizeStudyRoomSyncRoomUpdates(source.roomUpdates);

  if (!id || !ownerUid || !roomId || !actorUid || !Object.keys(roomUpdates).length) {
    return null;
  }

  return {
    id,
    ownerUid,
    roomId,
    actorUid,
    actorName: String(source.actorName || "Usuario").trim() || "Usuario",
    actorPhoto: String(source.actorPhoto || "").trim(),
    createdAt,
    roomCreatedAt,
    reason: String(source.reason || "").trim(),
    roomUpdates,
    friendUid: String(friendUid || "").trim()
  };
}

function collectSocialStudyRoomSyncOpsFromFriendDoc(friendUid, friendDocData = {}, ownerUid = ""){
  const safeFriendUid = String(friendUid || "").trim();
  const safeOwnerUid = String(ownerUid || currentUser?.uid || "").trim();
  if (!safeFriendUid || !safeOwnerUid) return [];
  if (!friendDocData || typeof friendDocData !== "object") return [];

  const rawSyncStore = friendDocData?.[SOCIAL_CHAT_STUDY_ROOM_SYNC_FIELD];
  if (!rawSyncStore || typeof rawSyncStore !== "object" || Array.isArray(rawSyncStore)) {
    return [];
  }

  const rawByOwner = rawSyncStore[safeOwnerUid];
  if (!rawByOwner || typeof rawByOwner !== "object" || Array.isArray(rawByOwner)) {
    return [];
  }

  const operations = [];
  Object.entries(rawByOwner).forEach(([opId, value]) => {
    const normalized = normalizeSocialStudyRoomSyncOp(value, opId, safeFriendUid);
    if (!normalized) return;
    operations.push(normalized);
  });

  operations.sort((a, b) => {
    const byTime = (Number(a?.createdAt) || 0) - (Number(b?.createdAt) || 0);
    if (byTime !== 0) return byTime;
    return String(a?.id || "").localeCompare(String(b?.id || ""), "es", { sensitivity: "base" });
  });
  return operations;
}

async function enqueueStudyRoomSyncRelayOperation({
  ownerUid = "",
  roomId = "",
  roomUpdates = {},
  reason = "",
  roomCreatedAt = 0
} = {}){
  const ownUid = String(currentUser?.uid || "").trim();
  const safeOwnerUid = String(ownerUid || "").trim();
  const safeRoomId = String(roomId || "").trim();
  if (!ownUid || !safeOwnerUid || !safeRoomId) return false;
  if (ownUid === safeOwnerUid) return false;

  const normalizedUpdates = filterStudyRoomSyncRoomUpdatesForActor(roomUpdates, ownUid);
  if (!Object.keys(normalizedUpdates).length) return false;

  const identity = getStudyRoomIdentity();
  const now = Date.now();
  const opId = `srs_${now}_${Math.random().toString(36).slice(2, 8)}`;
  let safeRoomCreatedAt = Math.max(0, Number(roomCreatedAt) || 0);
  if (!safeRoomCreatedAt) {
    const activeRoom = studyRoomsState.activeRoomData;
    if (
      activeRoom &&
      typeof activeRoom === "object" &&
      String(activeRoom.id || "").trim() === safeRoomId
    ) {
      safeRoomCreatedAt = Math.max(0, Number(activeRoom.createdAt) || 0);
    }
  }
  const payload = {
    id: opId,
    ownerUid: safeOwnerUid,
    roomId: safeRoomId,
    actorUid: ownUid,
    actorName: String(identity?.name || currentUser?.displayName || "Usuario").trim() || "Usuario",
    actorPhoto: String(identity?.photo || currentUser?.photoURL || "").trim(),
    createdAt: now,
    roomCreatedAt: safeRoomCreatedAt,
    reason: String(reason || "").trim(),
    roomUpdates: normalizedUpdates
  };

  logStudyRoomInviteDebug("RLY-01", "Encolando operación de sincronización de sala por fallback local.", {
    ownerUid: safeOwnerUid,
    roomId: safeRoomId,
    actorUid: ownUid,
    opId,
    reason: String(payload.reason || "").trim(),
    updateKeys: Object.keys(normalizedUpdates).slice(0, 16)
  }, "info");

  try {
    await setDoc(
      doc(db, "leaderboard", ownUid),
      {
        [SOCIAL_CHAT_STUDY_ROOM_SYNC_FIELD]: {
          [safeOwnerUid]: {
            [opId]: payload
          }
        }
      },
      { merge: true }
    );
    logStudyRoomInviteDebug("RLY-02", "Operación de sincronización de sala encolada.", {
      ownerUid: safeOwnerUid,
      roomId: safeRoomId,
      actorUid: ownUid,
      opId
    }, "ok");
    return true;
  } catch (err) {
    logStudyRoomInviteDebug("RLY-03", "No se pudo encolar operación de sincronización de sala.", {
      ownerUid: safeOwnerUid,
      roomId: safeRoomId,
      actorUid: ownUid,
      opId,
      permissionDenied: isFirestorePermissionError(err),
      code: String(err?.code || "").trim(),
      message: String(err?.message || "").trim()
    }, isFirestorePermissionError(err) ? "warn" : "error");
    if (!isFirestorePermissionError(err)) {
      console.warn("No se pudo encolar operación de sincronización de sala.", err);
    }
    return false;
  }
}

async function resolveCurrentOwnerStudyRoomForRelay(ownerUid = "", roomId = ""){
  const safeOwnerUid = String(ownerUid || "").trim();
  const safeRoomId = String(roomId || "").trim();
  if (!safeOwnerUid || !safeRoomId) return null;
  if (safeOwnerUid !== String(currentUser?.uid || "").trim()) return null;

  const activeRoomFromState = getCurrentUserOwnedActiveStudyRoom();
  if (
    activeRoomFromState &&
    typeof activeRoomFromState === "object" &&
    activeRoomFromState.isActive &&
    String(activeRoomFromState.id || "").trim() === safeRoomId
  ) {
    return activeRoomFromState;
  }

  try {
    const ownUserSnap = await getDoc(doc(db, "users", safeOwnerUid));
    if (ownUserSnap.exists()) {
      const ownedRoom = normalizeOwnedStudyRoomFromUserData(
        ownUserSnap.data() || {},
        safeOwnerUid
      );
      if (
        ownedRoom &&
        ownedRoom.isActive &&
        String(ownedRoom.id || "").trim() === safeRoomId
      ) {
        return ownedRoom;
      }
    }
  } catch (err) {
    if (!isFirestorePermissionError(err)) {
      console.warn("No se pudo validar sala owned actual para relay.", err);
    }
  }

  try {
    const primarySnap = await getDoc(doc(db, STUDY_ROOMS_COLLECTION, safeRoomId));
    if (primarySnap.exists()) {
      const primaryRoom = normalizeStudyRoomData(primarySnap.data() || {}, primarySnap.id);
      if (
        primaryRoom &&
        primaryRoom.isActive &&
        String(primaryRoom.createdByUid || "").trim() === safeOwnerUid
      ) {
        return primaryRoom;
      }
    }
  } catch (err) {
    if (!isFirestorePermissionError(err)) {
      console.warn("No se pudo validar sala principal actual para relay.", err);
    }
  }

  return null;
}

async function applySocialStudyRoomSyncOpFromFriend(operation = {}, friendUid = ""){
  const ownUid = String(currentUser?.uid || "").trim();
  const safeFriendUid = String(friendUid || "").trim();
  if (!ownUid) return false;
  if (!operation || typeof operation !== "object") return false;

  const safeOpId = String(operation.id || "").trim();
  const safeOwnerUid = String(operation.ownerUid || "").trim();
  const safeRoomId = String(operation.roomId || "").trim();
  const safeActorUid = String(operation.actorUid || "").trim();
  const safeCreatedAt = Math.max(0, Number(operation.createdAt) || 0);
  const safeRoomCreatedAt = Math.max(0, Number(operation.roomCreatedAt) || 0);
  const safeReason = String(operation.reason || "").trim();
  const normalizedRoomUpdates = filterStudyRoomSyncRoomUpdatesForActor(
    operation.roomUpdates,
    safeActorUid
  );
  if (!safeOpId || !safeOwnerUid || !safeRoomId || !safeActorUid || !Object.keys(normalizedRoomUpdates).length) {
    return false;
  }
  if (safeOwnerUid !== ownUid) return false;
  if (safeFriendUid && safeActorUid && safeActorUid !== safeFriendUid) {
    logStudyRoomInviteDebug("RLY-04", "Operación ignorada por actor distinto al friend listener.", {
      opId: safeOpId,
      friendUid: safeFriendUid,
      actorUid: safeActorUid
    }, "warn");
    return false;
  }
  if (safeRoomId !== ownUid) {
    logStudyRoomInviteDebug("RLY-05", "Operación ignorada por roomId inválido para el owner.", {
      opId: safeOpId,
      roomId: safeRoomId,
      ownerUid: safeOwnerUid
    }, "warn");
    return false;
  }
  if (safeCreatedAt > 0 && (Date.now() - safeCreatedAt) > STUDY_ROOM_SYNC_MAX_AGE_MS) {
    return false;
  }

  const ownerRoom = await resolveCurrentOwnerStudyRoomForRelay(safeOwnerUid, safeRoomId);
  if (!ownerRoom || !ownerRoom.isActive) {
    logStudyRoomInviteDebug("RLY-05A", "Relay ignorado: el creador ya no tiene una sala activa para ese roomId.", {
      opId: safeOpId,
      roomId: safeRoomId,
      ownerUid: safeOwnerUid,
      actorUid: safeActorUid,
      reason: safeReason
    }, "warn");
    return true;
  }

  const ownerRoomCreatedAt = Math.max(0, Number(ownerRoom.createdAt) || 0);
  const sameRoomByCreatedAt = !!(
    safeRoomCreatedAt > 0 &&
    ownerRoomCreatedAt > 0 &&
    safeRoomCreatedAt === ownerRoomCreatedAt
  );
  const plausibleByTimestamp = !!(
    safeRoomCreatedAt <= 0 &&
    safeCreatedAt > 0 &&
    ownerRoomCreatedAt > 0 &&
    (safeCreatedAt + STUDY_ROOM_SYNC_CREATED_AT_TOLERANCE_MS) >= ownerRoomCreatedAt
  );
  if (!sameRoomByCreatedAt && !plausibleByTimestamp) {
    logStudyRoomInviteDebug("RLY-05B", "Relay ignorado por desfase de creación de sala (operación vieja).", {
      opId: safeOpId,
      roomId: safeRoomId,
      ownerUid: safeOwnerUid,
      actorUid: safeActorUid,
      opCreatedAt: safeCreatedAt,
      opRoomCreatedAt: safeRoomCreatedAt,
      ownerRoomCreatedAt
    }, "warn");
    return true;
  }

  const ownerParticipants = ownerRoom.participantsByUid instanceof Map
    ? ownerRoom.participantsByUid
    : new Map();
  const ownerAllowed = ownerRoom.allowedByUid instanceof Map
    ? ownerRoom.allowedByUid
    : new Map();
  const ownerInvited = ownerRoom.invitedByUid instanceof Map
    ? ownerRoom.invitedByUid
    : new Map();
  const actorKnownToRoom = !!(
    ownerParticipants.has(safeActorUid) ||
    ownerAllowed.has(safeActorUid) ||
    ownerInvited.has(safeActorUid)
  );
  if (!actorKnownToRoom) {
    logStudyRoomInviteDebug("RLY-05C", "Relay ignorado: actor no pertenece ni está invitado a la sala actual.", {
      opId: safeOpId,
      roomId: safeRoomId,
      ownerUid: safeOwnerUid,
      actorUid: safeActorUid,
      reason: safeReason
    }, "warn");
    return true;
  }

  const roomUpdates = {
    ...normalizedRoomUpdates
  };
  if (!Object.prototype.hasOwnProperty.call(roomUpdates, "updatedAt")) {
    roomUpdates.updatedAt = Math.max(safeCreatedAt, Date.now());
  }

  const ownedUpdates = buildStudyRoomFirestoreUpdates(roomUpdates, {
    prefix: STUDY_ROOM_OWNED_FIELD
  });
  if (!Object.keys(ownedUpdates).length) return false;

  try {
    await updateDoc(doc(db, "users", ownUid), ownedUpdates);
  } catch (err) {
    logStudyRoomInviteDebug("RLY-06", "No se pudo aplicar operación relay en ruta owned del creador.", {
      opId: safeOpId,
      roomId: safeRoomId,
      actorUid: safeActorUid,
      reason: safeReason,
      permissionDenied: isFirestorePermissionError(err),
      code: String(err?.code || "").trim(),
      message: String(err?.message || "").trim()
    }, isFirestorePermissionError(err) ? "warn" : "error");
    if (!isFirestorePermissionError(err)) {
      console.warn("No se pudo aplicar operación de relay en sala owned.", err);
    }
    return false;
  }

  const sharedUpdates = buildStudyRoomFirestoreUpdates(roomUpdates, {
    prefix: STUDY_ROOM_SHARED_FIELD
  });
  if (Object.keys(sharedUpdates).length) {
    try {
      await updateDoc(doc(db, "leaderboard", ownUid), sharedUpdates);
    } catch (err) {
      logStudyRoomInviteDebug("RLY-06B", "No se pudo reflejar operación relay en snapshot shared.", {
        opId: safeOpId,
        roomId: safeRoomId,
        actorUid: safeActorUid,
        reason: safeReason,
        permissionDenied: isFirestorePermissionError(err),
        code: String(err?.code || "").trim(),
        message: String(err?.message || "").trim()
      }, isFirestorePermissionError(err) ? "warn" : "error");
      if (!isFirestorePermissionError(err)) {
        console.warn("No se pudo reflejar operación relay en snapshot shared.", err);
      }
    }
  }

  logStudyRoomInviteDebug("RLY-07", "Operación relay aplicada por el creador.", {
    opId: safeOpId,
    roomId: safeRoomId,
    actorUid: safeActorUid,
    reason: safeReason,
    updateKeys: Object.keys(roomUpdates).slice(0, 16)
  }, "ok");
  return true;
}

async function processSocialStudyRoomSyncOpsFromFriend(friendUid, friendDocData = {}){
  const ownUid = String(currentUser?.uid || "").trim();
  const safeFriendUid = String(friendUid || "").trim();
  if (!ownUid || !safeFriendUid) return 0;

  const operations = collectSocialStudyRoomSyncOpsFromFriendDoc(
    safeFriendUid,
    friendDocData,
    ownUid
  );
  if (!operations.length) return 0;

  if (!(socialState.studyRoomSyncAppliedOpIdsByFriendUid instanceof Map)) {
    socialState.studyRoomSyncAppliedOpIdsByFriendUid = new Map();
  }
  const alreadyAppliedOpIds = socialState.studyRoomSyncAppliedOpIdsByFriendUid.get(safeFriendUid) instanceof Set
    ? socialState.studyRoomSyncAppliedOpIdsByFriendUid.get(safeFriendUid)
    : new Set();

  let applied = 0;
  for (const operation of operations) {
    const safeOpId = String(operation?.id || "").trim();
    if (safeOpId && alreadyAppliedOpIds.has(safeOpId)) {
      continue;
    }
    // eslint-disable-next-line no-await-in-loop
    const done = await applySocialStudyRoomSyncOpFromFriend(operation, safeFriendUid);
    if (done && safeOpId) {
      alreadyAppliedOpIds.add(safeOpId);
      applied += 1;
    } else if (done) {
      applied += 1;
    }
  }
  while (alreadyAppliedOpIds.size > STUDY_ROOM_SYNC_TRACKED_OP_IDS_LIMIT) {
    const oldestTracked = alreadyAppliedOpIds.values().next().value;
    if (!oldestTracked) break;
    alreadyAppliedOpIds.delete(oldestTracked);
  }
  socialState.studyRoomSyncAppliedOpIdsByFriendUid.set(safeFriendUid, alreadyAppliedOpIds);

  if (applied > 0) {
    logStudyRoomInviteDebug("RLY-08", "Se aplicaron operaciones relay recibidas desde amigo.", {
      friendUid: safeFriendUid,
      ownerUid: ownUid,
      applied,
      total: operations.length
    }, "ok");
  }
  return applied;
}

function queueProcessSocialStudyRoomSyncOpsFromFriend(friendUid, friendDocData = {}){
  const ownUid = String(currentUser?.uid || "").trim();
  const safeFriendUid = String(friendUid || "").trim();
  if (!ownUid || !safeFriendUid) return;
  if (!friendDocData || typeof friendDocData !== "object") return;

  if (!(socialState.studyRoomSyncProcessQueueByFriendUid instanceof Map)) {
    socialState.studyRoomSyncProcessQueueByFriendUid = new Map();
  }
  const previousTask = socialState.studyRoomSyncProcessQueueByFriendUid.get(safeFriendUid);
  const safePreviousTask = previousTask instanceof Promise ? previousTask : Promise.resolve();

  const nextTask = safePreviousTask
    .catch(() => {})
    .then(() => processSocialStudyRoomSyncOpsFromFriend(safeFriendUid, friendDocData))
    .catch((err) => {
      if (!isFirestorePermissionError(err)) {
        console.warn("No se pudo procesar relay de sala desde amigo.", err);
      }
      return 0;
    });

  socialState.studyRoomSyncProcessQueueByFriendUid.set(safeFriendUid, nextTask);
}

function refreshSocialActiveChatMessages(){
  const activeFriendUid = String(socialState.chatActiveFriendUid || "").trim();
  if (!activeFriendUid || !currentUser?.uid) {
    socialState.chatMessages = [];
    return;
  }

  syncStudyRoomInviteAccessFromIncomingChatInvites(activeFriendUid, {
    friendData: socialState.chatFriendDocData || {}
  });

  socialState.chatMessages = buildSocialConversationMessages(activeFriendUid, {
    ownData: socialState.chatOwnDocData || {},
    friendData: socialState.chatFriendDocData || {}
  });
}

function syncSocialOwnReadMapFromOwnDocData(){
  const ownDocData =
    socialState.chatOwnDocData && typeof socialState.chatOwnDocData === "object"
      ? socialState.chatOwnDocData
      : {};
  const remoteReadMap = parseSocialChatReadsMap(ownDocData?.[SOCIAL_CHAT_READS_FIELD]);
  socialState.chatRemoteReadByUid = remoteReadMap;

  const currentReadMap = socialState.chatOwnReadByUid instanceof Map
    ? socialState.chatOwnReadByUid
    : new Map();
  const mergedReadMap = new Map(remoteReadMap);

  currentReadMap.forEach((value, peerUid) => {
    const safePeerUid = String(peerUid || "").trim();
    const timestamp = Math.max(0, Number(value) || 0);
    if (!safePeerUid || !timestamp) return;
    if (timestamp > Number(mergedReadMap.get(safePeerUid) || 0)) {
      mergedReadMap.set(safePeerUid, timestamp);
    }
  });

  socialState.chatOwnReadByUid = mergedReadMap;
  writeSocialReadCache(mergedReadMap);
}

function syncSocialActiveChatUnreadCount(){
  const safeFriendUid = String(socialState.chatActiveFriendUid || "").trim();
  const safeOwnUid = String(currentUser?.uid || "").trim();
  if (!safeFriendUid || !safeOwnUid) return;

  if (!(socialState.chatUnreadByUid instanceof Map)) {
    socialState.chatUnreadByUid = new Map();
  }
  if (!(socialState.chatOwnReadByUid instanceof Map)) {
    socialState.chatOwnReadByUid = new Map();
  }

  const readAt = Math.max(
    Number(socialState.chatOwnReadByUid.get(safeFriendUid) || 0),
    getSocialReadTimestampFromDoc(socialState.chatOwnDocData || {}, safeFriendUid)
  );
  const unread = countUnreadSocialMessagesFromFriendDoc(
    safeFriendUid,
    socialState.chatFriendDocData || {},
    safeOwnUid,
    readAt
  );

  if (unread > 0) {
    socialState.chatUnreadByUid.set(safeFriendUid, unread);
  } else {
    socialState.chatUnreadByUid.delete(safeFriendUid);
  }
}

async function flushSocialReadReceiptsQueue(){
  if (socialState.chatReadWorkerRunning) return;

  const ownUid = String(currentUser?.uid || "").trim();
  if (!ownUid) return;

  socialState.chatReadWorkerRunning = true;

  try {
    while (socialState.chatReadPendingByUid.size > 0) {
      const pendingEntries = Array.from(socialState.chatReadPendingByUid.entries());
      const [friendUid, pendingReadAt] = pendingEntries[0] || ["", 0];
      const safeFriendUid = String(friendUid || "").trim();
      const safeReadAt = Math.max(0, Number(pendingReadAt) || 0);

      socialState.chatReadPendingByUid.delete(safeFriendUid);
      if (!safeFriendUid || !safeReadAt) continue;

      const knownReadAt = Math.max(
        Number(socialState.chatRemoteReadByUid.get(safeFriendUid) || 0),
        getSocialReadTimestampFromDoc(socialState.chatOwnDocData || {}, safeFriendUid)
      );
      if (safeReadAt <= knownReadAt) continue;

      try {
        await setDoc(
          doc(db, "leaderboard", ownUid),
          {
            [SOCIAL_CHAT_READS_FIELD]: {
              [safeFriendUid]: {
                lastReadAt: safeReadAt,
                updatedAt: Date.now()
              }
            }
          },
          { merge: true }
        );
      } catch (err) {
        console.warn("No se pudo persistir recibo de lectura social.", err);
      }

      const currentOwnDocData =
        socialState.chatOwnDocData && typeof socialState.chatOwnDocData === "object"
          ? socialState.chatOwnDocData
          : {};
      const currentReadMap =
        currentOwnDocData[SOCIAL_CHAT_READS_FIELD] &&
        typeof currentOwnDocData[SOCIAL_CHAT_READS_FIELD] === "object"
          ? currentOwnDocData[SOCIAL_CHAT_READS_FIELD]
          : {};
      const currentEntry = currentReadMap[safeFriendUid];
      const currentEntryReadAt = typeof currentEntry === "number"
        ? Math.max(0, Number(currentEntry) || 0)
        : Math.max(0, Number(currentEntry?.lastReadAt) || 0);

      if (safeReadAt > currentEntryReadAt) {
        socialState.chatOwnDocData = {
          ...currentOwnDocData,
          [SOCIAL_CHAT_READS_FIELD]: {
            ...currentReadMap,
            [safeFriendUid]: {
              ...(currentEntry && typeof currentEntry === "object" ? currentEntry : {}),
              lastReadAt: safeReadAt,
              updatedAt: Date.now()
            }
          }
        };
      }
      socialState.chatRemoteReadByUid.set(safeFriendUid, safeReadAt);
      socialState.chatOwnReadByUid.set(safeFriendUid, safeReadAt);
      if (socialState.chatUnreadByUid instanceof Map) {
        socialState.chatUnreadByUid.set(safeFriendUid, 0);
      }
      writeSocialReadCache(socialState.chatOwnReadByUid);
    }
  } finally {
    socialState.chatReadWorkerRunning = false;
    if (socialState.chatReadPendingByUid.size > 0) {
      void flushSocialReadReceiptsQueue();
    }
  }
}

function queueSocialReadReceipt(friendUid, readAt){
  const safeFriendUid = String(friendUid || "").trim();
  const safeReadAt = Math.max(0, Number(readAt) || 0);
  if (!safeFriendUid || !safeReadAt || !currentUser?.uid) return;

  if (!(socialState.chatOwnReadByUid instanceof Map)) {
    socialState.chatOwnReadByUid = new Map();
  }
  if (!(socialState.chatRemoteReadByUid instanceof Map)) {
    socialState.chatRemoteReadByUid = new Map();
  }

  const alreadyKnownReadAt = Math.max(
    Number(socialState.chatRemoteReadByUid.get(safeFriendUid) || 0),
    getSocialReadTimestampFromDoc(socialState.chatOwnDocData || {}, safeFriendUid)
  );
  if (safeReadAt <= alreadyKnownReadAt) return;

  const pendingReadAt = Math.max(
    safeReadAt,
    Number(socialState.chatReadPendingByUid.get(safeFriendUid) || 0)
  );
  socialState.chatReadPendingByUid.set(safeFriendUid, pendingReadAt);
  socialState.chatOwnReadByUid.set(safeFriendUid, pendingReadAt);
  if (socialState.chatUnreadByUid instanceof Map) {
    socialState.chatUnreadByUid.set(safeFriendUid, 0);
  }
  writeSocialReadCache(socialState.chatOwnReadByUid);
  void flushSocialReadReceiptsQueue();
}

function syncSocialActiveChatReadReceipt(){
  const safeFriendUid = String(socialState.chatActiveFriendUid || "").trim();
  if (!safeFriendUid || !currentUser?.uid || socialState.chatMinimized) return;

  const messages = Array.isArray(socialState.chatMessages) ? socialState.chatMessages : [];
  let latestIncomingAt = 0;

  messages.forEach((message) => {
    if (String(message.fromUid || "") !== safeFriendUid) return;
    latestIncomingAt = Math.max(latestIncomingAt, Math.max(0, Number(message.createdAt) || 0));
  });

  if (!latestIncomingAt) return;
  queueSocialReadReceipt(safeFriendUid, latestIncomingAt);
}

function getSocialChatDeletePromptForFriend(friendUid = ""){
  const safeFriendUid = String(friendUid || "").trim();
  if (!safeFriendUid) return null;

  const prompt = socialState.chatDeletePrompt;
  if (!prompt || typeof prompt !== "object") return null;

  const promptFriendUid = String(prompt.friendUid || "").trim();
  const promptMessageId = String(prompt.messageId || "").trim();
  if (!promptFriendUid || !promptMessageId) return null;
  if (promptFriendUid !== safeFriendUid) return null;

  return {
    friendUid: promptFriendUid,
    messageId: promptMessageId
  };
}

function closeSocialChatDeletePrompt({ patch = true } = {}){
  if (!socialState.chatDeletePrompt) return;
  socialState.chatDeletePrompt = null;
  if (patch) {
    patchSocialFriendsUI();
  }
}

function openSocialChatDeletePrompt(friendUid, messageId){
  const safeFriendUid = String(friendUid || "").trim();
  const safeMessageId = String(messageId || "").trim();
  const ownUid = String(currentUser?.uid || "").trim();
  if (!safeFriendUid || !safeMessageId || !ownUid) return false;
  if (safeFriendUid !== String(socialState.chatActiveFriendUid || "").trim()) return false;

  const messages = Array.isArray(socialState.chatMessages) ? socialState.chatMessages : [];
  const messageToDelete = messages.find((message) => {
    return (
      String(message?.id || "").trim() === safeMessageId &&
      String(message?.fromUid || "").trim() === ownUid
    );
  });
  if (!messageToDelete) return false;

  socialState.chatDeletePrompt = {
    friendUid: safeFriendUid,
    messageId: safeMessageId
  };
  closeSocialChatPlusMenus(board);
  patchSocialFriendsUI();
  return true;
}

async function deleteSocialChatMessageForAll(friendUid, messageId){
  const safeFriendUid = String(friendUid || "").trim();
  const safeMessageId = String(messageId || "").trim();
  const ownUid = String(currentUser?.uid || "").trim();
  if (!safeFriendUid || !safeMessageId || !ownUid) {
    showToast("No se pudo eliminar el mensaje.");
    return false;
  }

  const messages = Array.isArray(socialState.chatMessages) ? socialState.chatMessages : [];
  const ownMessage = messages.find((message) => {
    if (String(message?.id || "").trim() !== safeMessageId) return false;
    if (String(message?.fromUid || "").trim() !== ownUid) return false;
    const messageToUid = String(message?.toUid || safeFriendUid).trim();
    return messageToUid === safeFriendUid;
  });
  if (!ownMessage) {
    showToast("Solo podés eliminar mensajes enviados por vos.");
    return false;
  }

  try {
    await updateDoc(doc(db, "leaderboard", ownUid), {
      [`${SOCIAL_CHAT_OUTBOX_FIELD}.${safeFriendUid}.${safeMessageId}`]: deleteField()
    });
  } catch (err) {
    if (isFirestorePermissionError(err)) {
      showToast("No hay permisos suficientes para eliminar mensajes.");
      return false;
    }
    console.error("No se pudo eliminar mensaje social para todos.", err);
    showToast("No se pudo eliminar el mensaje.");
    return false;
  }

  const ownDocData =
    socialState.chatOwnDocData && typeof socialState.chatOwnDocData === "object"
      ? socialState.chatOwnDocData
      : {};
  const currentOutbox =
    ownDocData[SOCIAL_CHAT_OUTBOX_FIELD] &&
    typeof ownDocData[SOCIAL_CHAT_OUTBOX_FIELD] === "object"
      ? ownDocData[SOCIAL_CHAT_OUTBOX_FIELD]
      : {};
  const currentThread =
    currentOutbox[safeFriendUid] &&
    typeof currentOutbox[safeFriendUid] === "object"
      ? currentOutbox[safeFriendUid]
      : null;

  if (currentThread && Object.prototype.hasOwnProperty.call(currentThread, safeMessageId)) {
    const nextThread = { ...currentThread };
    delete nextThread[safeMessageId];

    const nextOutbox = { ...currentOutbox };
    if (Object.keys(nextThread).length) {
      nextOutbox[safeFriendUid] = nextThread;
    } else {
      delete nextOutbox[safeFriendUid];
    }

    socialState.chatOwnDocData = {
      ...ownDocData,
      [SOCIAL_CHAT_OUTBOX_FIELD]: nextOutbox
    };
  }

  closeSocialChatDeletePrompt({ patch: false });
  refreshSocialActiveChatMessages();
  syncSocialActiveChatUnreadCount();
  syncSocialActiveChatReadReceipt();
  patchSocialFriendsUI();
  showToast("Mensaje eliminado para todos.");
  return true;
}

function closeSocialChatSession({ silent = false } = {}){
  socialState.chatDeletePrompt = null;

  if (typeof socialState.chatOwnUnsub === "function") {
    try {
      socialState.chatOwnUnsub();
    } catch (_error) {}
  }

  if (typeof socialState.chatFriendUnsub === "function") {
    try {
      socialState.chatFriendUnsub();
    } catch (_error) {}
  }

  socialState.chatOwnUnsub = null;
  socialState.chatFriendUnsub = null;
  socialState.chatActiveFriendUid = "";
  socialState.chatMinimized = false;
  socialState.chatMessages = [];
  socialState.chatLoading = false;
  socialState.chatError = "";
  socialState.chatOwnDocData = null;
  socialState.chatFriendDocData = null;
  socialState.chatOwnReady = false;
  socialState.chatFriendReady = false;

  if (!silent) {
    patchSocialFriendsUI();
  }
}

function openSocialChatSession(friendUid){
  const safeFriendUid = String(friendUid || "").trim();
  if (!safeFriendUid || !currentUser?.uid) return;

  const isSameChatOpen =
    socialState.chatActiveFriendUid === safeFriendUid &&
    (typeof socialState.chatOwnUnsub === "function" || typeof socialState.chatFriendUnsub === "function");

  if (isSameChatOpen) {
    socialState.chatDeletePrompt = null;
    socialState.chatMinimized = !socialState.chatMinimized;
    patchSocialFriendsUI();
    return;
  }

  closeSocialChatSession({ silent: true });

  socialState.chatActiveFriendUid = safeFriendUid;
  socialState.chatMinimized = false;
  socialState.chatMessages = [];
  socialState.chatLoading = true;
  socialState.chatError = "";
  socialState.chatOwnDocData = null;
  socialState.chatFriendDocData = null;
  socialState.chatDeletePrompt = null;
  socialState.chatOwnReady = false;
  socialState.chatFriendReady = false;
  if (socialState.chatUnreadByUid instanceof Map) {
    socialState.chatUnreadByUid.set(safeFriendUid, 0);
  }
  patchSocialFriendsUI();

  const ownRef = doc(db, "leaderboard", currentUser.uid);
  const friendRef = doc(db, "leaderboard", safeFriendUid);

  const syncLoadingState = () => {
    socialState.chatLoading = !(socialState.chatOwnReady && socialState.chatFriendReady);
  };

  socialState.chatOwnUnsub = onSnapshot(
    ownRef,
    (snapshot) => {
      if (socialState.chatActiveFriendUid !== safeFriendUid) return;
      socialState.chatOwnDocData = snapshot.exists() ? (snapshot.data() || {}) : {};
      socialState.chatOwnReady = true;
      socialState.chatError = "";
      syncSocialOwnReadMapFromOwnDocData();
      syncLoadingState();
      refreshSocialActiveChatMessages();
      syncSocialActiveChatUnreadCount();
      syncSocialActiveChatReadReceipt();
      patchSocialFriendsUI();
    },
    (err) => {
      if (socialState.chatActiveFriendUid !== safeFriendUid) return;
      socialState.chatOwnDocData = {};
      socialState.chatOwnReady = true;
      socialState.chatError = isFirestorePermissionError(err)
        ? "No hay permisos para leer tu historial de chat."
        : "No se pudo cargar el chat.";
      syncSocialOwnReadMapFromOwnDocData();
      syncLoadingState();
      refreshSocialActiveChatMessages();
      syncSocialActiveChatUnreadCount();
      syncSocialActiveChatReadReceipt();
      patchSocialFriendsUI();
    }
  );

  socialState.chatFriendUnsub = onSnapshot(
    friendRef,
    (snapshot) => {
      if (socialState.chatActiveFriendUid !== safeFriendUid) return;
      socialState.chatFriendDocData = snapshot.exists() ? (snapshot.data() || {}) : {};
      queueProcessSocialStudyRoomSyncOpsFromFriend(safeFriendUid, socialState.chatFriendDocData);
      socialState.chatFriendReady = true;
      socialState.chatError = "";
      syncLoadingState();
      refreshSocialActiveChatMessages();
      syncSocialActiveChatUnreadCount();
      syncSocialActiveChatReadReceipt();
      patchSocialFriendsUI();
    },
    (err) => {
      if (socialState.chatActiveFriendUid !== safeFriendUid) return;
      socialState.chatFriendDocData = {};
      socialState.chatFriendReady = true;
      socialState.chatError = isFirestorePermissionError(err)
        ? "No hay permisos para leer mensajes de este amigo."
        : "No se pudo actualizar el chat.";
      syncLoadingState();
      refreshSocialActiveChatMessages();
      syncSocialActiveChatUnreadCount();
      syncSocialActiveChatReadReceipt();
      patchSocialFriendsUI();
    }
  );
}

async function sendSocialChatEntry(targetUid, entry = {}){
  const safeTargetUid = String(targetUid || "").trim();
  const ownUid = String(currentUser?.uid || "").trim();
  if (!safeTargetUid || !ownUid) return null;

  const text = String(entry?.text || "").trim().slice(0, SOCIAL_CHAT_MAX_LENGTH);
  if (!text) return null;

  const now = Math.max(0, Number(entry?.createdAt) || Date.now());
  const messageId = String(entry?.id || `m_${now}_${Math.random().toString(36).slice(2, 8)}`).trim();
  if (!messageId) return null;
  const kind = normalizeSocialChatMessageKind(entry?.kind || entry?.type);
  const payload = {
    id: messageId,
    fromUid: ownUid,
    toUid: safeTargetUid,
    text,
    createdAt: now
  };
  if (kind !== SOCIAL_CHAT_KIND_MESSAGE) {
    payload.kind = kind;
  }
  if (kind === SOCIAL_CHAT_KIND_STUDY_ROOM_INVITE) {
    const invitePayload = normalizeSocialChatStudyRoomInvitePayload(entry?.studyRoomInvite, {
      roomId: entry?.roomId,
      roomTitle: entry?.roomTitle,
      invitedByUid: ownUid,
      invitedByName: entry?.invitedByName || entry?.inviterName,
      roomAccessSource: entry?.roomAccessSource || entry?.roomSource
    });
    payload.studyRoomInvite = invitePayload;
  }

  await setDoc(
    doc(db, "leaderboard", ownUid),
    {
      [SOCIAL_CHAT_OUTBOX_FIELD]: {
        [safeTargetUid]: {
          [messageId]: payload
        }
      }
    },
    { merge: true }
  );

  const currentOwnDocData =
    socialState.chatOwnDocData && typeof socialState.chatOwnDocData === "object"
      ? socialState.chatOwnDocData
      : {};
  const currentOutbox =
    currentOwnDocData[SOCIAL_CHAT_OUTBOX_FIELD] &&
    typeof currentOwnDocData[SOCIAL_CHAT_OUTBOX_FIELD] === "object"
      ? currentOwnDocData[SOCIAL_CHAT_OUTBOX_FIELD]
      : {};
  const currentThread =
    currentOutbox[safeTargetUid] && typeof currentOutbox[safeTargetUid] === "object"
      ? currentOutbox[safeTargetUid]
      : {};

  socialState.chatOwnDocData = {
    ...currentOwnDocData,
    [SOCIAL_CHAT_OUTBOX_FIELD]: {
      ...currentOutbox,
      [safeTargetUid]: {
        ...currentThread,
        [messageId]: payload
      }
    }
  };

  refreshSocialActiveChatMessages();
  if (socialState.chatDraftByUid instanceof Map) {
    socialState.chatDraftByUid.set(safeTargetUid, "");
  }
  patchSocialFriendsUI();
  if (kind === SOCIAL_CHAT_KIND_MESSAGE) {
    void registerCollaborativeProgress("totalMessagesSent", 1, {
      silentAchievements: false
    });
  }
  return payload;
}

async function sendSocialChatMessage(targetUid, rawMessage){
  const sentPayload = await sendSocialChatEntry(targetUid, {
    text: String(rawMessage || "")
  });
  return !!sentPayload;
}

async function sendSocialChatStudyRoomInviteMessage(
  targetUid,
  {
    roomId = "",
    roomTitle = "Sala de estudio",
    inviterName = "",
    roomAccessSource = ""
  } = {}
){
  const safeRoomId = String(roomId || "").trim();
  const safeRoomTitle = String(roomTitle || "Sala de estudio").trim() || "Sala de estudio";
  const safeInviterName = String(
    inviterName ||
    currentUser?.displayName ||
    "Usuario"
  ).trim() || "Usuario";
  const safeRoomAccessSource = normalizeStudyRoomInviteAccessSource(roomAccessSource);

  const sentPayload = await sendSocialChatEntry(targetUid, {
    kind: SOCIAL_CHAT_KIND_STUDY_ROOM_INVITE,
    text: `Invitacion para sala ${safeRoomTitle} enviada`,
    studyRoomInvite: {
      roomId: safeRoomId,
      roomTitle: safeRoomTitle,
      invitedByUid: String(currentUser?.uid || "").trim(),
      invitedByName: safeInviterName,
      roomAccessSource: safeRoomAccessSource
    }
  });

  return !!sentPayload;
}

function getIncomingSocialChatStudyRoomInviteMessage(friendUid, messageId){
  const safeFriendUid = String(friendUid || "").trim();
  const safeMessageId = String(messageId || "").trim();
  const ownUid = String(currentUser?.uid || "").trim();
  if (!safeFriendUid || !safeMessageId || !ownUid) return null;

  const messages = Array.isArray(socialState.chatMessages) ? socialState.chatMessages : [];
  const matched = messages.find((message) => {
    if (!message || typeof message !== "object") return false;
    if (String(message.id || "").trim() !== safeMessageId) return false;
    if (String(message.fromUid || "").trim() !== safeFriendUid) return false;
    if (String(message.toUid || "").trim() !== ownUid) return false;
    return isSocialChatStudyRoomInviteMessage(message);
  });

  return matched && typeof matched === "object" ? matched : null;
}

async function persistSocialChatStudyRoomInviteResponse(friendUid, message = {}, status = ""){
  const safeFriendUid = String(friendUid || "").trim();
  const safeMessageId = String(message?.id || "").trim();
  const ownUid = String(currentUser?.uid || "").trim();
  if (!safeFriendUid || !safeMessageId || !ownUid) return false;

  const invitePayload = normalizeSocialChatStudyRoomInvitePayload(message?.studyRoomInvite, {
    roomId: message?.roomId,
    roomTitle: message?.roomTitle,
    invitedByUid: message?.fromUid || safeFriendUid,
    invitedByName: message?.invitedByName,
    roomAccessSource: message?.roomAccessSource || message?.roomSource
  });
  const normalizedStatus = normalizeSocialChatStudyRoomInviteStatus(status);
  const now = Date.now();
  const responsePayload = {
    status: normalizedStatus,
    roomId: String(invitePayload.roomId || "").trim(),
    roomTitle: String(invitePayload.roomTitle || "Sala de estudio").trim() || "Sala de estudio",
    invitedByUid: String(invitePayload.invitedByUid || safeFriendUid).trim(),
    invitedByName: String(invitePayload.invitedByName || "").trim(),
    roomAccessSource: String(invitePayload.roomAccessSource || "").trim(),
    updatedAt: now,
    respondedAt: now
  };

  try {
    await setDoc(
      doc(db, "leaderboard", ownUid),
      {
        [SOCIAL_CHAT_STUDY_ROOM_INVITES_FIELD]: {
          [safeFriendUid]: {
            [safeMessageId]: responsePayload
          }
        }
      },
      { merge: true }
    );
  } catch (err) {
    if (isFirestorePermissionError(err)) {
      showToast("No hay permisos para actualizar esta invitación.");
      return false;
    }
    console.error("No se pudo guardar respuesta de invitación de sala en chat.", err);
    showToast("No se pudo actualizar la invitación.");
    return false;
  }

  const ownDocData =
    socialState.chatOwnDocData && typeof socialState.chatOwnDocData === "object"
      ? socialState.chatOwnDocData
      : {};
  const currentInviteStore =
    ownDocData[SOCIAL_CHAT_STUDY_ROOM_INVITES_FIELD] &&
    typeof ownDocData[SOCIAL_CHAT_STUDY_ROOM_INVITES_FIELD] === "object" &&
    !Array.isArray(ownDocData[SOCIAL_CHAT_STUDY_ROOM_INVITES_FIELD])
      ? ownDocData[SOCIAL_CHAT_STUDY_ROOM_INVITES_FIELD]
      : {};
  const currentFriendStore =
    currentInviteStore[safeFriendUid] &&
    typeof currentInviteStore[safeFriendUid] === "object" &&
    !Array.isArray(currentInviteStore[safeFriendUid])
      ? currentInviteStore[safeFriendUid]
      : {};

  socialState.chatOwnDocData = {
    ...ownDocData,
    [SOCIAL_CHAT_STUDY_ROOM_INVITES_FIELD]: {
      ...currentInviteStore,
      [safeFriendUid]: {
        ...currentFriendStore,
        [safeMessageId]: responsePayload
      }
    }
  };

  refreshSocialActiveChatMessages();
  syncSocialActiveChatUnreadCount();
  syncSocialActiveChatReadReceipt();
  patchSocialFriendsUI();
  return true;
}

async function resolveStudyRoomInvitationTargetRoom(roomId, inviterUid = ""){
  const safeRoomId = String(roomId || "").trim();
  const safeInviterUid = String(inviterUid || "").trim();
  logStudyRoomInviteDebug("RES-01", "Resolviendo sala destino de invitación.", {
    roomId: safeRoomId,
    inviterUid: safeInviterUid,
    cachedRoomsCount: Array.isArray(studyRoomsState.rooms) ? studyRoomsState.rooms.length : 0,
    activeRoomId: String(studyRoomsState.activeRoomId || "").trim()
  });
  if (!safeRoomId) {
    logStudyRoomInviteDebug("RES-02", "Fallo: roomId ausente.", { roomId: safeRoomId }, "warn");
    return { isActive: false, reason: "missing-room-id", roomData: null };
  }

  const activeRoom = studyRoomsState.activeRoomData;
  if (
    activeRoom &&
    typeof activeRoom === "object" &&
    String(activeRoom.id || "").trim() === safeRoomId
  ) {
    logStudyRoomInviteDebug("RES-03", "Sala resuelta desde activeRoom en memoria.", {
      roomId: safeRoomId,
      isActive: activeRoom.isActive !== false
    }, "ok");
    return {
      isActive: activeRoom.isActive !== false,
      reason: activeRoom.isActive === false ? "closed" : "active-room",
      roomData: activeRoom
    };
  }

  const roomFromList = studyRoomsState.rooms.find((entry) => {
    return String(entry?.id || "").trim() === safeRoomId;
  });
  if (roomFromList) {
    logStudyRoomInviteDebug("RES-04", "Sala resuelta desde lista local.", {
      roomId: safeRoomId,
      isActive: roomFromList.isActive !== false,
      createdByUid: String(roomFromList.createdByUid || "").trim()
    }, "ok");
    return {
      isActive: roomFromList.isActive !== false,
      reason: roomFromList.isActive === false ? "closed" : "rooms-list",
      roomData: roomFromList
    };
  }

  try {
    const roomSnapshot = await getDoc(doc(db, STUDY_ROOMS_COLLECTION, safeRoomId));
    if (!roomSnapshot.exists()) {
      logStudyRoomInviteDebug("RES-05", "Sala no existe en studyRooms.", { roomId: safeRoomId }, "warn");
      return { isActive: false, reason: "missing", roomData: null };
    }
    const normalizedRoom = normalizeStudyRoomData(roomSnapshot.data() || {}, roomSnapshot.id);
    if (!normalizedRoom) {
      logStudyRoomInviteDebug("RES-06", "Sala inválida en studyRooms.", { roomId: safeRoomId }, "warn");
      return { isActive: false, reason: "invalid", roomData: null };
    }
    logStudyRoomInviteDebug("RES-07", "Sala resuelta desde studyRooms.", {
      roomId: safeRoomId,
      isActive: normalizedRoom.isActive !== false,
      createdByUid: String(normalizedRoom.createdByUid || "").trim()
    }, "ok");
    return {
      isActive: normalizedRoom.isActive !== false,
      reason: normalizedRoom.isActive === false ? "closed" : "primary",
      roomData: normalizedRoom
    };
  } catch (err) {
    logStudyRoomInviteDebug("RES-08", "Error leyendo studyRooms para invitación.", {
      roomId: safeRoomId,
      permissionDenied: isFirestorePermissionError(err),
      code: String(err?.code || "").trim(),
      message: String(err?.message || "").trim()
    }, isFirestorePermissionError(err) ? "warn" : "error");
    if (!isFirestorePermissionError(err)) {
      console.warn("No se pudo verificar sala de invitación en studyRooms.", err);
    }
  }

  if (safeInviterUid) {
    try {
      const inviterUserSnapshot = await getDoc(doc(db, "users", safeInviterUid));
      if (inviterUserSnapshot.exists()) {
        const normalizedOwnedRoom = normalizeOwnedStudyRoomFromUserData(
          inviterUserSnapshot.data() || {},
          safeInviterUid
        );
        if (normalizedOwnedRoom && String(normalizedOwnedRoom.id || "").trim() === safeRoomId) {
          logStudyRoomInviteDebug("RES-09A", "Sala resuelta desde users/{owner}.studyRoomOwned.", {
            roomId: safeRoomId,
            inviterUid: safeInviterUid
          }, "ok");
          return {
            isActive: normalizedOwnedRoom.isActive !== false,
            reason: normalizedOwnedRoom.isActive === false ? "closed-owned" : "owned",
            roomData: normalizedOwnedRoom
          };
        }
      }
    } catch (err) {
      logStudyRoomInviteDebug("RES-09B", "Error leyendo users del creador para invitación.", {
        roomId: safeRoomId,
        inviterUid: safeInviterUid,
        permissionDenied: isFirestorePermissionError(err),
        code: String(err?.code || "").trim(),
        message: String(err?.message || "").trim()
      }, isFirestorePermissionError(err) ? "warn" : "error");
      if (!isFirestorePermissionError(err)) {
        console.warn("No se pudo verificar sala de invitación en users del creador.", err);
      }
    }

    try {
      const inviterSnapshot = await getDoc(doc(db, "leaderboard", safeInviterUid));
      if (inviterSnapshot.exists()) {
        const inviterData = inviterSnapshot.data() || {};
        const normalizedSharedRoom = normalizeSharedStudyRoomFromLeaderboard(
          inviterData,
          safeInviterUid
        );
        if (normalizedSharedRoom && String(normalizedSharedRoom.id || "").trim() === safeRoomId) {
          logStudyRoomInviteDebug("RES-09C", "Sala resuelta desde snapshot shared en leaderboard del creador.", {
            roomId: safeRoomId,
            inviterUid: safeInviterUid
          }, "ok");
          return {
            isActive: normalizedSharedRoom.isActive !== false,
            reason: normalizedSharedRoom.isActive === false ? "closed-shared" : "shared",
            roomData: normalizedSharedRoom
          };
        }
        const normalizedPublicRoom = normalizePublicStudyRoomFromLeaderboard(
          inviterData,
          safeInviterUid
        );
        if (normalizedPublicRoom && String(normalizedPublicRoom.id || "").trim() === safeRoomId) {
          logStudyRoomInviteDebug("RES-09", "Sala resuelta desde resumen público del creador.", {
            roomId: safeRoomId,
            inviterUid: safeInviterUid
          }, "ok");
          return { isActive: true, reason: "public-summary", roomData: normalizedPublicRoom };
        }
      }
    } catch (err) {
      logStudyRoomInviteDebug("RES-10", "Error leyendo leaderboard del creador para invitación.", {
        roomId: safeRoomId,
        inviterUid: safeInviterUid,
        permissionDenied: isFirestorePermissionError(err),
        code: String(err?.code || "").trim(),
        message: String(err?.message || "").trim()
      }, isFirestorePermissionError(err) ? "warn" : "error");
      if (!isFirestorePermissionError(err)) {
        console.warn("No se pudo verificar sala de invitación en leaderboard.", err);
      }
    }
  }

  logStudyRoomInviteDebug("RES-11", "No se pudo resolver sala destino de invitación.", {
    roomId: safeRoomId,
    inviterUid: safeInviterUid
  }, "warn");
  return { isActive: false, reason: "unavailable", roomData: null };
}

function waitForStudyRoomSessionReady(roomId, { timeoutMs = 4500, pollMs = 120 } = {}){
  const safeRoomId = String(roomId || "").trim();
  if (!safeRoomId) {
    return Promise.resolve({ ready: false, reason: "missing-room" });
  }

  const safeTimeoutMs = Math.max(300, Number(timeoutMs) || 0);
  const safePollMs = Math.max(60, Number(pollMs) || 0);
  const startedAt = Date.now();

  return new Promise((resolve) => {
    const checkState = () => {
      const activeRoomId = String(studyRoomsState.activeRoomId || "").trim();
      if (activeRoomId !== safeRoomId) {
        resolve({ ready: false, reason: "switched" });
        return;
      }

      const activeRoomData = studyRoomsState.activeRoomData && typeof studyRoomsState.activeRoomData === "object"
        ? studyRoomsState.activeRoomData
        : null;
      const activeRoomDataId = activeRoomData
        ? String(activeRoomData.id || "").trim()
        : "";
      if (activeRoomDataId === safeRoomId) {
        resolve({ ready: true, reason: "ready" });
        return;
      }

      const activeRoomError = String(studyRoomsState.activeRoomError || "").trim();
      if (activeRoomError) {
        resolve({ ready: false, reason: "error", error: activeRoomError });
        return;
      }

      if (Date.now() - startedAt >= safeTimeoutMs) {
        resolve({ ready: false, reason: "timeout" });
        return;
      }

      setTimeout(checkState, safePollMs);
    };

    checkState();
  });
}

async function claimStudyRoomInviteMembership(
  roomId,
  {
    invitedByUid = "",
    invitedByName = "",
    roomAccessSource = ""
  } = {}
){
  const safeRoomId = String(roomId || "").trim();
  const identity = getStudyRoomIdentity();
  if (!safeRoomId || !identity?.uid) {
    logStudyRoomInviteDebug("CLM-01", "No se puede reclamar membresía (roomId o usuario inválido).", {
      roomId: safeRoomId,
      identityUid: String(identity?.uid || "").trim()
    }, "warn");
    return false;
  }

  if (!(studyRoomsState.joinAnnouncementSyncedByRoomId instanceof Set)) {
    studyRoomsState.joinAnnouncementSyncedByRoomId = new Set();
  }
  const shouldAppendJoinMessage = !studyRoomsState.joinAnnouncementSyncedByRoomId.has(safeRoomId);
  const safeInvitedByUid = String(invitedByUid || "").trim();
  const safeInvitedByName = String(invitedByName || "").trim();
  const safeRoomAccessSource = normalizeStudyRoomInviteAccessSource(roomAccessSource);
  logStudyRoomInviteDebug("CLM-02", "Intentando reclamar membresía de invitación.", {
    roomId: safeRoomId,
    userUid: identity.uid,
    invitedByUid: safeInvitedByUid,
    appendJoinMessage: shouldAppendJoinMessage,
    roomAccessSource: safeRoomAccessSource
  });

  const now = Date.now();
  const joinMessageId = shouldAppendJoinMessage
    ? `sc_${now}_${Math.random().toString(36).slice(2, 8)}`
    : "";
  const payload = {
    updatedAt: now
  };
  payload[`allowed.${identity.uid}`] = {
    uid: identity.uid,
    addedAt: now,
    invitedByUid: safeInvitedByUid,
    invitedByName: safeInvitedByName
  };
  payload[`invited.${identity.uid}`] = {
    uid: identity.uid,
    invitedAt: now,
    invitedByUid: safeInvitedByUid,
    invitedByName: safeInvitedByName
  };
  payload[`participants.${identity.uid}`] = {
    uid: identity.uid,
    name: identity.name,
    photo: identity.photo,
    joinedAt: now,
    updatedAt: now
  };
  payload[`boards.${identity.uid}`] = {
    uid: identity.uid,
    name: identity.name,
    photo: identity.photo,
    tasks: {},
    updatedAt: now
  };

  if (shouldAppendJoinMessage && joinMessageId) {
    payload[`chat.${joinMessageId}`] = {
      id: joinMessageId,
      uid: identity.uid,
      name: identity.name,
      photo: identity.photo,
      kind: "system",
      text: `${identity.name} se ha unido a la sala`,
      createdAt: now
    };
  }

  const ownedPayload = {
    [`${STUDY_ROOM_OWNED_FIELD}.allowed.${identity.uid}`]: {
      uid: identity.uid,
      addedAt: now,
      invitedByUid: safeInvitedByUid,
      invitedByName: safeInvitedByName
    },
    [`${STUDY_ROOM_OWNED_FIELD}.invited.${identity.uid}`]: {
      uid: identity.uid,
      invitedAt: now,
      invitedByUid: safeInvitedByUid,
      invitedByName: safeInvitedByName
    },
    [`${STUDY_ROOM_OWNED_FIELD}.participants.${identity.uid}`]: {
      uid: identity.uid,
      name: identity.name,
      photo: identity.photo,
      joinedAt: now,
      updatedAt: now
    },
    [`${STUDY_ROOM_OWNED_FIELD}.boards.${identity.uid}`]: {
      uid: identity.uid,
      name: identity.name,
      photo: identity.photo,
      tasks: {},
      updatedAt: now
    },
    [`${STUDY_ROOM_OWNED_FIELD}.updatedAt`]: now
  };
  if (shouldAppendJoinMessage && joinMessageId) {
    ownedPayload[`${STUDY_ROOM_OWNED_FIELD}.chat.${joinMessageId}`] = {
      id: joinMessageId,
      uid: identity.uid,
      name: identity.name,
      photo: identity.photo,
      kind: "system",
      text: `${identity.name} se ha unido a la sala`,
      createdAt: now
    };
  }

  if (safeRoomAccessSource === "owned" && safeInvitedByUid) {
    try {
      await updateDoc(doc(db, "users", safeInvitedByUid), ownedPayload);
      if (shouldAppendJoinMessage) {
        studyRoomsState.joinAnnouncementSyncedByRoomId.add(safeRoomId);
      }
      logStudyRoomInviteDebug("CLM-02A", "Membresía confirmada en owned (prioridad por source).", {
        roomId: safeRoomId,
        ownerUid: safeInvitedByUid,
        userUid: identity.uid
      }, "ok");
      return true;
    } catch (preferredOwnedErr) {
      logStudyRoomInviteDebug("CLM-02B", "Falló intento prioritario en owned, se probará primary.", {
        roomId: safeRoomId,
        ownerUid: safeInvitedByUid,
        userUid: identity.uid,
        permissionDenied: isFirestorePermissionError(preferredOwnedErr),
        code: String(preferredOwnedErr?.code || "").trim(),
        message: String(preferredOwnedErr?.message || "").trim()
      }, isFirestorePermissionError(preferredOwnedErr) ? "warn" : "error");
    }
  }

  try {
    await updateDoc(doc(db, STUDY_ROOMS_COLLECTION, safeRoomId), payload);
    if (shouldAppendJoinMessage) {
      studyRoomsState.joinAnnouncementSyncedByRoomId.add(safeRoomId);
    }
    logStudyRoomInviteDebug("CLM-03", "Membresía confirmada en studyRooms.", {
      roomId: safeRoomId,
      userUid: identity.uid
    }, "ok");
    return true;
  } catch (err) {
    const shouldTryOwnedFallback = isFirestorePermissionError(err) || isFirestoreNotFoundError(err);
    logStudyRoomInviteDebug("CLM-04", "Falló confirmación en studyRooms.", {
      roomId: safeRoomId,
      userUid: identity.uid,
      permissionDenied: isFirestorePermissionError(err),
      notFound: isFirestoreNotFoundError(err),
      shouldTryOwnedFallback,
      invitedByUid: safeInvitedByUid,
      code: String(err?.code || "").trim(),
      message: String(err?.message || "").trim()
    }, shouldTryOwnedFallback ? "warn" : "error");
    if (!shouldTryOwnedFallback || !safeInvitedByUid) {
      if (!isFirestorePermissionError(err)) {
        console.warn("No se pudo confirmar membresía al aceptar invitación de sala.", err);
      }
      return false;
    }

    try {
      await updateDoc(doc(db, "users", safeInvitedByUid), ownedPayload);
      if (shouldAppendJoinMessage) {
        studyRoomsState.joinAnnouncementSyncedByRoomId.add(safeRoomId);
      }
      logStudyRoomInviteDebug("CLM-05", "Membresía confirmada en fallback owned.", {
        roomId: safeRoomId,
        ownerUid: safeInvitedByUid,
        userUid: identity.uid
      }, "ok");
      return true;
    } catch (ownedErr) {
      logStudyRoomInviteDebug("CLM-06", "Falló fallback owned para reclamar membresía.", {
        roomId: safeRoomId,
        ownerUid: safeInvitedByUid,
        userUid: identity.uid,
        permissionDenied: isFirestorePermissionError(ownedErr),
        code: String(ownedErr?.code || "").trim(),
        message: String(ownedErr?.message || "").trim()
      }, isFirestorePermissionError(ownedErr) ? "warn" : "error");
      if (!isFirestorePermissionError(ownedErr)) {
        console.warn("No se pudo confirmar membresía en sala local al aceptar invitación.", ownedErr);
      }
      return false;
    }
  }
}

async function openStudyRoomSessionFromInvite(
  roomId,
  {
    roomTitle = "Sala de estudio",
    invitedByUid = "",
    roomAccessSource = ""
  } = {}
){
  const safeRoomId = String(roomId || "").trim();
  if (!safeRoomId || !currentUser?.uid) {
    logStudyRoomInviteDebug("OPN-01", "No se puede abrir sala desde invitación (roomId o usuario inválido).", {
      roomId: safeRoomId,
      currentUid: String(currentUser?.uid || "").trim()
    }, "warn");
    return false;
  }
  const safeInvitedByUid = String(invitedByUid || "").trim();
  const safeRoomAccessSource = normalizeStudyRoomInviteAccessSource(roomAccessSource);
  logStudyRoomInviteDebug("OPN-02", "Abriendo sala desde invitación.", {
    roomId: safeRoomId,
    roomTitle: String(roomTitle || "").trim(),
    invitedByUid: safeInvitedByUid,
    currentUid: String(currentUser?.uid || "").trim(),
    roomAccessSource: safeRoomAccessSource
  });

  const activeRoom = studyRoomsState.activeRoomData;
  const ownUid = String(currentUser?.uid || "").trim();
  const isSwitchingRoom = !!(
    activeRoom &&
    typeof activeRoom === "object" &&
    String(activeRoom.id || "").trim() &&
    String(activeRoom.id || "").trim() !== safeRoomId
  );
  const isOwnerSwitchingFromOwnRoom = !!(
    isSwitchingRoom &&
    String(activeRoom.createdByUid || "").trim() === ownUid
  );
  if (isOwnerSwitchingFromOwnRoom) {
    const confirmClose = await openStudyRoomActionConfirmDialog({
      title: "Cerrar sala actual",
      message: "Si entrás a otra sala, tu sala actual se va a cerrar para todos y se van a borrar tareas, chat, título e integrantes.",
      confirmLabel: "Cerrar y entrar",
      cancelLabel: "Cancelar"
    });
    if (!confirmClose) {
      logStudyRoomInviteDebug("OPN-03", "Ingreso cancelado por confirmación al cerrar sala propia.", {
        roomId: safeRoomId
      }, "warn");
      return false;
    }
  }

  if (
    safeRoomAccessSource === "owned" &&
    safeInvitedByUid &&
    safeInvitedByUid !== ownUid
  ) {
    logStudyRoomInviteDebug("OPN-03A", "Intentando apertura prioritaria por source owned.", {
      roomId: safeRoomId,
      ownerUid: safeInvitedByUid
    }, "info");
    persistStudyRoomActiveSession(safeInvitedByUid, currentUser?.uid);
    subscribeActiveOwnedStudyRoom(safeInvitedByUid);
    startStudyRoomSessionTracking(safeInvitedByUid);
    await setViewMode(VIEW_MODE_STUDY_ROOMS);
    const preferredOwnedJoin = await waitForStudyRoomSessionReady(safeInvitedByUid);
    logStudyRoomInviteDebug("OPN-03B", "Resultado de apertura prioritaria por owned.", {
      ownerUid: safeInvitedByUid,
      ready: !!preferredOwnedJoin?.ready,
      reason: String(preferredOwnedJoin?.reason || "").trim(),
      error: String(preferredOwnedJoin?.error || "").trim()
    }, preferredOwnedJoin?.ready ? "ok" : "warn");
    if (preferredOwnedJoin.ready) {
      showToast(`Entraste a la sala ${String(roomTitle || "Sala de estudio").trim() || "Sala de estudio"}.`);
      return true;
    }
    const leftOwnedAttempt = await leaveStudyRoomSession({ silent: true });
    logStudyRoomInviteDebug("OPN-03C", "Limpieza tras intento owned fallido para probar ruta primaria.", {
      ownerUid: safeInvitedByUid,
      leftOwnedAttempt
    }, leftOwnedAttempt ? "ok" : "warn");
  }

  const opened = await openStudyRoomSession(safeRoomId, {
    skipListAccessCheck: true
  });
  logStudyRoomInviteDebug("OPN-04", "Resultado de openStudyRoomSession para invitación.", {
    roomId: safeRoomId,
    opened
  }, opened ? "ok" : "warn");
  if (!opened) return false;

  await setViewMode(VIEW_MODE_STUDY_ROOMS);
  const joinResult = await waitForStudyRoomSessionReady(safeRoomId);
  logStudyRoomInviteDebug("OPN-05", "Resultado de espera de sesión en sala principal.", {
    roomId: safeRoomId,
    ready: !!joinResult?.ready,
    reason: String(joinResult?.reason || "").trim(),
    error: String(joinResult?.error || "").trim()
  }, joinResult?.ready ? "ok" : "warn");
  if (!joinResult.ready) {
    if (joinResult.reason === "switched") {
      const activeRoomSource = String(studyRoomsState.activeRoomSource || "").trim().toLowerCase();
      const activeRoomOwnerUid = String(studyRoomsState.activeRoomOwnerUid || "").trim();
      const activeRoomId = String(studyRoomsState.activeRoomId || "").trim();
      const expectedOwnerUid = String(safeInvitedByUid || "").trim();
      const switchedToOwned = (
        activeRoomSource === "owned" &&
        !!activeRoomOwnerUid &&
        (!!expectedOwnerUid ? activeRoomOwnerUid === expectedOwnerUid : true)
      );
      logStudyRoomInviteDebug("OPN-05A", "La sesión cambió durante la espera de sala principal.", {
        roomId: safeRoomId,
        activeRoomId,
        activeRoomSource,
        activeRoomOwnerUid,
        expectedOwnerUid,
        switchedToOwned
      }, switchedToOwned ? "warn" : "info");
      if (switchedToOwned) {
        const switchedJoinResult = await waitForStudyRoomSessionReady(activeRoomOwnerUid);
        logStudyRoomInviteDebug("OPN-05B", "Resultado de espera tras switch a owned.", {
          ownerUid: activeRoomOwnerUid,
          ready: !!switchedJoinResult?.ready,
          reason: String(switchedJoinResult?.reason || "").trim(),
          error: String(switchedJoinResult?.error || "").trim()
        }, switchedJoinResult?.ready ? "ok" : "warn");
        if (switchedJoinResult.ready) {
          showToast(`Entraste a la sala ${String(roomTitle || "Sala de estudio").trim() || "Sala de estudio"}.`);
          return true;
        }
      }
    }
    if (joinResult.reason === "error") {
      const roomError = String(joinResult.error || "").trim();
      const ownUid = String(currentUser?.uid || "").trim();
      const canTryOwnedFallback = !!safeInvitedByUid && safeInvitedByUid !== ownUid;
      logStudyRoomInviteDebug("OPN-06", "Fallo apertura principal, evaluando fallback owned.", {
        roomId: safeRoomId,
        roomError,
        canTryOwnedFallback,
        invitedByUid: safeInvitedByUid,
        ownUid
      }, canTryOwnedFallback ? "warn" : "error");
      if (canTryOwnedFallback) {
        persistStudyRoomActiveSession(safeInvitedByUid, currentUser?.uid);
        subscribeActiveOwnedStudyRoom(safeInvitedByUid);
        startStudyRoomSessionTracking(safeInvitedByUid);
        const ownedJoinResult = await waitForStudyRoomSessionReady(safeInvitedByUid);
        logStudyRoomInviteDebug("OPN-07", "Resultado de espera en fallback owned.", {
          ownerUid: safeInvitedByUid,
          ready: !!ownedJoinResult?.ready,
          reason: String(ownedJoinResult?.reason || "").trim(),
          error: String(ownedJoinResult?.error || "").trim()
        }, ownedJoinResult?.ready ? "ok" : "warn");
        if (ownedJoinResult.ready) {
          showToast(`Entraste a la sala ${String(roomTitle || "Sala de estudio").trim() || "Sala de estudio"}.`);
          return true;
        }
      }
      if (roomError) {
        showToast(roomError);
      }
      logStudyRoomInviteDebug("OPN-08", "No se pudo abrir sala desde invitación tras fallback.", {
        roomId: safeRoomId,
        roomError
      }, "error");
      return false;
    }
    if (joinResult.reason === "timeout") {
      showToast("No se pudo confirmar el ingreso a la sala. Probá de nuevo.");
    }
    logStudyRoomInviteDebug("OPN-09", "No se confirmó ingreso a sala (estado no listo).", {
      roomId: safeRoomId,
      reason: String(joinResult?.reason || "").trim()
    }, "warn");
    return false;
  }
  showToast(`Entraste a la sala ${String(roomTitle || "Sala de estudio").trim() || "Sala de estudio"}.`);
  logStudyRoomInviteDebug("OPN-10", "Ingreso a sala confirmado desde invitación.", {
    roomId: safeRoomId
  }, "ok");
  return true;
}

async function respondToSocialChatStudyRoomInvite(friendUid, messageId, action = "accept"){
  const safeFriendUid = String(friendUid || "").trim();
  const safeMessageId = String(messageId || "").trim();
  const safeAction = String(action || "").trim().toLowerCase();
  if (!safeFriendUid || !safeMessageId) {
    logStudyRoomInviteDebug("ACC-01", "Parámetros inválidos al responder invitación.", {
      friendUid: safeFriendUid,
      messageId: safeMessageId,
      action: safeAction
    }, "warn");
    return false;
  }
  if (safeAction !== "accept" && safeAction !== "reject") {
    logStudyRoomInviteDebug("ACC-02", "Acción inválida al responder invitación.", {
      friendUid: safeFriendUid,
      messageId: safeMessageId,
      action: safeAction
    }, "warn");
    return false;
  }
  logStudyRoomInviteDebug("ACC-03", "Procesando respuesta de invitación.", {
    friendUid: safeFriendUid,
    messageId: safeMessageId,
    action: safeAction
  });

  const inviteMessage = getIncomingSocialChatStudyRoomInviteMessage(safeFriendUid, safeMessageId);
  if (!inviteMessage) {
    logStudyRoomInviteDebug("ACC-04", "No se encontró el mensaje de invitación en chat activo.", {
      friendUid: safeFriendUid,
      messageId: safeMessageId
    }, "warn");
    showToast("La invitación ya no está disponible.");
    return false;
  }

  const currentStatus = normalizeSocialChatStudyRoomInviteStatus(inviteMessage.inviteResponseStatus);
  if (currentStatus !== SOCIAL_CHAT_STUDY_ROOM_INVITE_STATUS_PENDING) {
    logStudyRoomInviteDebug("ACC-05", "La invitación ya tenía estado final.", {
      friendUid: safeFriendUid,
      messageId: safeMessageId,
      status: currentStatus
    }, "info");
    return true;
  }

  const invitePayload = normalizeSocialChatStudyRoomInvitePayload(inviteMessage.studyRoomInvite, {
    roomId: inviteMessage.roomId,
    roomTitle: inviteMessage.roomTitle,
    invitedByUid: inviteMessage.fromUid || safeFriendUid,
    invitedByName: inviteMessage.invitedByName,
    roomAccessSource: inviteMessage.roomAccessSource || inviteMessage.roomSource
  });
  const roomId = String(invitePayload.roomId || "").trim();
  const roomTitle = String(invitePayload.roomTitle || "Sala de estudio").trim() || "Sala de estudio";
  logStudyRoomInviteDebug("ACC-06", "Payload de invitación normalizado.", {
    friendUid: safeFriendUid,
    messageId: safeMessageId,
    roomId,
    roomTitle,
    invitedByUid: String(invitePayload.invitedByUid || safeFriendUid).trim(),
    roomAccessSource: String(invitePayload.roomAccessSource || "").trim()
  });

  if (safeAction === "reject") {
    const rejected = await persistSocialChatStudyRoomInviteResponse(
      safeFriendUid,
      inviteMessage,
      SOCIAL_CHAT_STUDY_ROOM_INVITE_STATUS_REJECTED
    );
    logStudyRoomInviteDebug("ACC-07", "Resultado de rechazo de invitación.", {
      friendUid: safeFriendUid,
      messageId: safeMessageId,
      rejected
    }, rejected ? "ok" : "error");
    if (rejected) {
      showToast(`Invitación a ${roomTitle} rechazada.`);
    }
    return rejected;
  }

  const resolvedRoom = await resolveStudyRoomInvitationTargetRoom(roomId, invitePayload.invitedByUid || safeFriendUid);
  logStudyRoomInviteDebug("ACC-08", "Resultado de resolución de sala al aceptar.", {
    roomId,
    isActive: !!resolvedRoom?.isActive,
    reason: String(resolvedRoom?.reason || "").trim(),
    createdByUid: String(resolvedRoom?.roomData?.createdByUid || "").trim()
  }, resolvedRoom?.isActive ? "ok" : "warn");
  if (!resolvedRoom.isActive) {
    await persistSocialChatStudyRoomInviteResponse(
      safeFriendUid,
      inviteMessage,
      SOCIAL_CHAT_STUDY_ROOM_INVITE_STATUS_ROOM_CLOSED
    );
    showToast(`La sala ${roomTitle} ya fue cerrada.`);
    return false;
  }

  grantCurrentUserStudyRoomInviteAccess(roomId, {
    invitedByUid: invitePayload.invitedByUid || safeFriendUid,
    roomTitle,
    roomAccessSource: invitePayload.roomAccessSource
  });
  logStudyRoomInviteDebug("ACC-09", "Acceso local por invitación registrado.", {
    roomId,
    invitedByUid: String(invitePayload.invitedByUid || safeFriendUid).trim()
  }, "ok");

  const membershipClaimed = await claimStudyRoomInviteMembership(roomId, {
    invitedByUid: invitePayload.invitedByUid || safeFriendUid,
    invitedByName: invitePayload.invitedByName,
    roomAccessSource: invitePayload.roomAccessSource
  });
  logStudyRoomInviteDebug("ACC-10", "Resultado de claim de membresía al aceptar.", {
    roomId,
    membershipClaimed
  }, membershipClaimed ? "ok" : "warn");

  const joined = await openStudyRoomSessionFromInvite(roomId, {
    roomTitle,
    invitedByUid: invitePayload.invitedByUid || safeFriendUid,
    roomAccessSource: invitePayload.roomAccessSource
  });
  logStudyRoomInviteDebug("ACC-11", "Resultado de apertura de sala tras aceptar.", {
    roomId,
    joined
  }, joined ? "ok" : "error");
  if (!joined) {
    return false;
  }

  const accepted = await persistSocialChatStudyRoomInviteResponse(
    safeFriendUid,
    inviteMessage,
    SOCIAL_CHAT_STUDY_ROOM_INVITE_STATUS_ACCEPTED
  );
  logStudyRoomInviteDebug("ACC-12", "Resultado de persistencia de aceptación en chat.", {
    roomId,
    accepted
  }, accepted ? "ok" : "error");
  if (!accepted) return false;
  return true;
}

function combineSocialCollections(){
  const mergedFriends = new Map();
  const mergedIncoming = new Map();

  socialState.localFriends.forEach((entry) => {
    if (!entry?.uid) return;
    mergedFriends.set(entry.uid, entry);
  });

  socialState.remoteFriends.forEach((entry) => {
    if (!entry?.uid) return;
    const previous = mergedFriends.get(entry.uid);
    if (!previous || (Number(entry.addedAt) || 0) >= (Number(previous.addedAt) || 0)) {
      mergedFriends.set(entry.uid, entry);
    }
  });

  const pushIncoming = (entry) => {
    if (!entry?.uid) return;
    if (mergedFriends.has(entry.uid)) return;

    const rejectedAt = socialState.rejectedByUid.get(entry.uid) || 0;
    const requestedAt = Math.max(0, Number(entry.requestedAt) || 0);
    if (rejectedAt && requestedAt && requestedAt <= rejectedAt) return;

    const previous = mergedIncoming.get(entry.uid);
    if (!previous || requestedAt >= (Number(previous.requestedAt) || 0)) {
      mergedIncoming.set(entry.uid, entry);
    }
  };

  socialState.localIncomingRequests.forEach(pushIncoming);
  socialState.remoteIncomingRequests.forEach(pushIncoming);

  const friends = Array.from(mergedFriends.values()).sort((a, b) => {
    return String(a.name || "").localeCompare(String(b.name || ""), "es", { sensitivity: "base" });
  });

  const incomingRequests = Array.from(mergedIncoming.values()).sort((a, b) => {
    const byTime = (Number(b.requestedAt) || 0) - (Number(a.requestedAt) || 0);
    if (byTime !== 0) return byTime;
    return String(a.name || "").localeCompare(String(b.name || ""), "es", { sensitivity: "base" });
  });

  socialState.friends = friends;
  socialState.incomingRequests = incomingRequests;
  socialState.friendsByUid = new Map(friends.map((friend) => [friend.uid, friend]));
  socialState.incomingByUid = new Map(incomingRequests.map((request) => [request.uid, request]));

  const outgoingPendingByUid = new Map();
  socialState.localOutgoingRequests.forEach((entry) => {
    const uid = String(entry?.uid || "").trim();
    if (!uid) return;
    if (String(entry.status || "pending") !== "pending") return;
    if (socialState.friendsByUid.has(uid)) return;
    if (socialState.incomingByUid.has(uid)) return;
    outgoingPendingByUid.set(uid, entry);
  });
  socialState.outgoingPendingByUid = outgoingPendingByUid;
  ensureSocialUnreadLiveListeners();
}

function getSocialUnreadTotalCount(){
  if (!(socialState.chatUnreadByUid instanceof Map)) return 0;
  let total = 0;
  socialState.chatUnreadByUid.forEach((value) => {
    const count = Math.max(0, Number(value) || 0);
    if (!count) return;
    total += count;
  });
  return total;
}

function syncSocialNavUnreadBadge(scope = board){
  const root = scope instanceof HTMLElement ? scope : board;
  if (!(root instanceof HTMLElement)) return;

  const socialButtons = root.querySelectorAll(`.summary-nav-item[data-view="${VIEW_MODE_SOCIAL}"]`);
  if (!socialButtons.length) return;

  const totalUnread = getSocialUnreadTotalCount();
  const badgeLabel = totalUnread > 99 ? "99+" : String(totalUnread);
  const safeTotalLabel = totalUnread === 1 ? "1 mensaje sin leer" : `${totalUnread} mensajes sin leer`;

  socialButtons.forEach((button) => {
    if (!(button instanceof HTMLButtonElement)) return;

    button.classList.toggle("has-unread", totalUnread > 0);
    if (totalUnread > 0) {
      button.dataset.unreadTotal = String(totalUnread);
      button.setAttribute("aria-label", `Social (${safeTotalLabel})`);

      let badge = button.querySelector(".summary-nav-unread-badge");
      if (!(badge instanceof HTMLElement)) {
        badge = document.createElement("span");
        badge.className = "summary-nav-unread-badge";
        badge.setAttribute("aria-hidden", "true");
        button.appendChild(badge);
      }
      badge.textContent = badgeLabel;
      return;
    }

    button.removeAttribute("data-unread-total");
    button.setAttribute("aria-label", "Social");
    const badge = button.querySelector(".summary-nav-unread-badge");
    if (badge instanceof HTMLElement) {
      badge.remove();
    }
  });
}

function stopSocialUnreadLiveListeners(){
  if (typeof socialState.chatUnreadLiveOwnUnsub === "function") {
    try {
      socialState.chatUnreadLiveOwnUnsub();
    } catch (_error) {}
  }
  socialState.chatUnreadLiveOwnUnsub = null;

  if (!(socialState.chatUnreadLiveFriendUnsubByUid instanceof Map)) {
    socialState.chatUnreadLiveFriendUnsubByUid = new Map();
  }
  socialState.chatUnreadLiveFriendUnsubByUid.forEach((unsub) => {
    if (typeof unsub !== "function") return;
    try {
      unsub();
    } catch (_error) {}
  });
  socialState.chatUnreadLiveFriendUnsubByUid.clear();

  socialState.chatUnreadLiveFriendDocByUid = new Map();
  socialState.chatUnreadLiveOwnReadByUid = new Map();
  socialState.studyRoomSyncProcessQueueByFriendUid = new Map();
  socialState.studyRoomSyncAppliedOpIdsByFriendUid = new Map();
}

function syncSocialUnreadFromLiveSnapshots({ patch = true } = {}){
  const ownUid = String(currentUser?.uid || "").trim();
  if (!ownUid) return;

  if (!(socialState.chatUnreadLiveFriendDocByUid instanceof Map)) {
    socialState.chatUnreadLiveFriendDocByUid = new Map();
  }
  if (!(socialState.chatUnreadLiveOwnReadByUid instanceof Map)) {
    socialState.chatUnreadLiveOwnReadByUid = new Map();
  }
  if (!(socialState.chatUnreadByUid instanceof Map)) {
    socialState.chatUnreadByUid = new Map();
  }

  const friendUidSet = new Set(
    (Array.isArray(socialState.friends) ? socialState.friends : [])
      .map((friend) => String(friend?.uid || "").trim())
      .filter(Boolean)
  );
  const nextUnreadMap = new Map();

  friendUidSet.forEach((friendUid) => {
    const friendDocData = socialState.chatUnreadLiveFriendDocByUid.get(friendUid);
    if (!friendDocData || typeof friendDocData !== "object") {
      const fallbackUnread = Math.max(0, Number(socialState.chatUnreadByUid.get(friendUid) || 0));
      if (fallbackUnread > 0) {
        nextUnreadMap.set(friendUid, fallbackUnread);
      }
      return;
    }

    const readAt = Math.max(
      Number(socialState.chatUnreadLiveOwnReadByUid.get(friendUid) || 0),
      Number(socialState.chatOwnReadByUid?.get(friendUid) || 0),
      getSocialReadTimestampFromDoc(socialState.chatOwnDocData || {}, friendUid)
    );
    const unreadCount = countUnreadSocialMessagesFromFriendDoc(
      friendUid,
      friendDocData,
      ownUid,
      readAt
    );
    if (unreadCount > 0) {
      nextUnreadMap.set(friendUid, unreadCount);
    }
  });

  socialState.chatUnreadByUid = nextUnreadMap;
  syncSocialActiveChatUnreadCount();

  if (patch) {
    patchSocialFriendsUI();
  } else {
    syncSocialNavUnreadBadge(board);
  }
}

function ensureSocialUnreadLiveListeners(){
  const ownUid = String(currentUser?.uid || "").trim();
  if (!ownUid) {
    stopSocialUnreadLiveListeners();
    return;
  }

  if (!(socialState.chatUnreadLiveFriendUnsubByUid instanceof Map)) {
    socialState.chatUnreadLiveFriendUnsubByUid = new Map();
  }
  if (!(socialState.chatUnreadLiveFriendDocByUid instanceof Map)) {
    socialState.chatUnreadLiveFriendDocByUid = new Map();
  }
  if (!(socialState.chatUnreadLiveOwnReadByUid instanceof Map)) {
    socialState.chatUnreadLiveOwnReadByUid = new Map();
  }

  if (typeof socialState.chatUnreadLiveOwnUnsub !== "function") {
    socialState.chatUnreadLiveOwnUnsub = onSnapshot(
      doc(db, "leaderboard", ownUid),
      (snapshot) => {
        const ownData = snapshot.exists() ? (snapshot.data() || {}) : {};
        socialState.chatUnreadLiveOwnReadByUid = parseSocialChatReadsMap(
          ownData?.[SOCIAL_CHAT_READS_FIELD]
        );
        syncSocialUnreadFromLiveSnapshots();
      },
      (err) => {
        if (!isFirestorePermissionError(err)) {
          console.warn("No se pudo suscribir lectura social propia para no leídos.", err);
        }
      }
    );
  }

  const desiredFriendUids = new Set(
    (Array.isArray(socialState.friends) ? socialState.friends : [])
      .map((friend) => String(friend?.uid || "").trim())
      .filter(Boolean)
      .filter((uid) => uid !== ownUid)
  );

  socialState.chatUnreadLiveFriendUnsubByUid.forEach((unsub, friendUid) => {
    if (desiredFriendUids.has(friendUid)) return;
    if (typeof unsub === "function") {
      try {
        unsub();
      } catch (_error) {}
    }
    socialState.chatUnreadLiveFriendUnsubByUid.delete(friendUid);
    socialState.chatUnreadLiveFriendDocByUid.delete(friendUid);
    if (socialState.studyRoomSyncProcessQueueByFriendUid instanceof Map) {
      socialState.studyRoomSyncProcessQueueByFriendUid.delete(friendUid);
    }
    if (socialState.studyRoomSyncAppliedOpIdsByFriendUid instanceof Map) {
      socialState.studyRoomSyncAppliedOpIdsByFriendUid.delete(friendUid);
    }
  });

  desiredFriendUids.forEach((friendUid) => {
    if (socialState.chatUnreadLiveFriendUnsubByUid.has(friendUid)) return;

    const friendUnsub = onSnapshot(
      doc(db, "leaderboard", friendUid),
      (snapshot) => {
        socialState.chatUnreadLiveFriendDocByUid.set(
          friendUid,
          snapshot.exists() ? (snapshot.data() || {}) : {}
        );
        queueProcessSocialStudyRoomSyncOpsFromFriend(
          friendUid,
          socialState.chatUnreadLiveFriendDocByUid.get(friendUid) || {}
        );
        syncSocialUnreadFromLiveSnapshots();
      },
      (err) => {
        if (!isFirestorePermissionError(err)) {
          console.warn("No se pudo suscribir chat de amigo para no leídos.", err);
        }
        socialState.chatUnreadLiveFriendDocByUid.delete(friendUid);
        syncSocialUnreadFromLiveSnapshots();
      }
    );

    socialState.chatUnreadLiveFriendUnsubByUid.set(friendUid, friendUnsub);
  });

  if (!desiredFriendUids.size) {
    socialState.chatUnreadLiveFriendDocByUid.clear();
    if (socialState.studyRoomSyncProcessQueueByFriendUid instanceof Map) {
      socialState.studyRoomSyncProcessQueueByFriendUid.clear();
    }
    if (socialState.studyRoomSyncAppliedOpIdsByFriendUid instanceof Map) {
      socialState.studyRoomSyncAppliedOpIdsByFriendUid.clear();
    }
    socialState.chatUnreadByUid = new Map();
    syncSocialActiveChatUnreadCount();
    syncSocialNavUnreadBadge(board);
  }
}

function getCurrentUserSocialIdentity(){
  if (!currentUser?.uid) return null;

  return normalizeSocialUser({
    uid: currentUser.uid,
    name: currentUser.displayName || "Usuario",
    email: currentUser.email || "",
    photo: currentUser.photoURL || ""
  });
}

async function maybeHandleStudyRoomClosureSummaryFromUserData(data = {}){
  const ownUid = String(currentUser?.uid || "").trim();
  if (!ownUid) return false;

  const summary = normalizeStudyRoomClosureSummary(data?.[STUDY_ROOM_CLOSURE_SUMMARY_FIELD]);
  if (!summary) return false;

  const seenSummaryId = readStoredStudyRoomClosureSummarySeenId(ownUid);
  const alreadyHandled =
    summary.id === seenSummaryId ||
    summary.id === lastHandledStudyRoomClosureSummaryId;

  if (alreadyHandled) {
    if (summary.id !== lastHandledStudyRoomClosureSummaryId) {
      lastHandledStudyRoomClosureSummaryId = summary.id;
      try {
        await updateDoc(doc(db, "users", ownUid), {
          [STUDY_ROOM_CLOSURE_SUMMARY_FIELD]: deleteField()
        });
      } catch (_error) {}
    }
    return false;
  }

  lastHandledStudyRoomClosureSummaryId = summary.id;
  persistStudyRoomClosureSummarySeenId(summary.id, ownUid);

  const activeRoomId = String(studyRoomsState.activeRoomId || "").trim();
  const activeRoomDataId = String(studyRoomsState.activeRoomData?.id || "").trim();
  const shouldCloseActiveSession = !!summary.roomId && (
    summary.roomId === activeRoomId ||
    summary.roomId === activeRoomDataId
  );
  revokeCurrentUserStudyRoomInviteAccess(summary.roomId, summary.closedByUid);
  if (shouldCloseActiveSession) {
    try {
      await leaveStudyRoomSession({ silent: true, forceLocal: true });
    } catch (leaveErr) {
      if (!isFirestorePermissionError(leaveErr)) {
        console.warn("No se pudo cerrar la sesión local tras resumen de cierre de sala.", leaveErr);
      }
    }
  }

  openStudyRoomClosureSummaryDialog(summary);

  try {
    await updateDoc(doc(db, "users", ownUid), {
      [STUDY_ROOM_CLOSURE_SUMMARY_FIELD]: deleteField()
    });
  } catch (_error) {}

  return true;
}

function applySocialStateFromUserData(data = {}, { allowToast = false } = {}){
  const previousIncomingCount = socialState.incomingRequests.length;

  socialState.localFriends = parseSocialUserMap(data?.[SOCIAL_FRIENDS_FIELD]);
  socialState.localIncomingRequests = parseSocialUserMap(data?.[SOCIAL_INCOMING_REQUESTS_FIELD]);
  socialState.localOutgoingRequests = parseSocialOutgoingMap(data?.[SOCIAL_OUTGOING_REQUESTS_FIELD]);
  socialState.rejectedByUid = parseSocialTimestampMap(data?.[SOCIAL_REJECTED_REQUESTS_FIELD]);
  combineSocialCollections();

  if (allowToast && socialState.hydrated && socialState.incomingRequests.length > previousIncomingCount) {
    const newCount = socialState.incomingRequests.length - previousIncomingCount;
    showToast(
      newCount === 1
        ? "Tenés una nueva solicitud de amistad."
        : `Tenés ${newCount} nuevas solicitudes de amistad.`
    );
  }

  socialState.hydrated = true;
  void refreshSocialRemoteState();
  if (isPlayerReadyForAchievementChecks()) {
    checkAchievements({ silent: false });
  }
}

async function refreshSocialRemoteState({ force = false } = {}){
  if (!currentUser?.uid) return;

  const now = Date.now();
  const hasFreshRemoteCache =
    !force &&
    socialState.remoteFetchedAt > 0 &&
    (now - socialState.remoteFetchedAt) < SOCIAL_REMOTE_CACHE_TTL_MS;

  if (hasFreshRemoteCache) return;

  const runId = ++socialState.remoteFetchToken;
  const incomingPath = `${SOCIAL_OUTGOING_REQUESTS_FIELD}.${currentUser.uid}.status`;
  const acceptedPath = `${SOCIAL_ACCEPTED_FLAGS_FIELD}.${currentUser.uid}`;

  let incomingSnapshot;
  let acceptedSnapshot;
  let ownLeaderboardSnapshot;

  try {
    [incomingSnapshot, acceptedSnapshot, ownLeaderboardSnapshot] = await Promise.all([
      getDocs(
        query(
          collection(db, "leaderboard"),
          where(incomingPath, "==", "pending"),
          limit(120)
        )
      ),
      getDocs(
        query(
          collection(db, "leaderboard"),
          where(acceptedPath, "==", true),
          limit(120)
        )
      ),
      getDoc(doc(db, "leaderboard", currentUser.uid))
    ]);
  } catch (err) {
    if (runId !== socialState.remoteFetchToken) return;
    if (isFirestorePermissionError(err)) {
      socialState.remoteIncomingRequests = [];
      socialState.remoteFriends = [];
      socialState.chatUnreadByUid = new Map();
      socialState.chatRemoteReadByUid = new Map();
      socialState.chatOwnReadByUid = readSocialReadCache(currentUser.uid);
    } else {
      console.warn("No se pudo actualizar estado social remoto.", err);
    }
    socialState.remoteFetchedAt = Date.now();
    combineSocialCollections();
    patchSocialRequestsUI();
    patchSocialSearchResultsUI();
    patchSocialFriendsUI();
    return;
  }

  if (runId !== socialState.remoteFetchToken) return;

  const remoteIncoming = [];
  const remoteFriends = [];
  const ownLeaderboardData = ownLeaderboardSnapshot?.exists() ? (ownLeaderboardSnapshot.data() || {}) : {};
  const remoteReadByUid = parseSocialChatReadsMap(ownLeaderboardData?.[SOCIAL_CHAT_READS_FIELD]);
  const localReadByUid = readSocialReadCache(currentUser.uid);
  const ownReadByUid = new Map(remoteReadByUid);
  localReadByUid.forEach((value, peerUid) => {
    const safePeerUid = String(peerUid || "").trim();
    const timestamp = Math.max(0, Number(value) || 0);
    if (!safePeerUid || !timestamp) return;
    if (timestamp > Number(ownReadByUid.get(safePeerUid) || 0)) {
      ownReadByUid.set(safePeerUid, timestamp);
    }
  });
  const remoteUnreadByUid = new Map();
  const friendLeaderboardDataByUid = new Map();

  incomingSnapshot?.forEach((docSnap) => {
    if (!docSnap.exists()) return;
    if (docSnap.id === currentUser.uid) return;

    const data = docSnap.data() || {};
    const outgoingMap = data?.[SOCIAL_OUTGOING_REQUESTS_FIELD];
    if (!outgoingMap || typeof outgoingMap !== "object") return;

    const requestData = outgoingMap[currentUser.uid];
    if (!requestData || typeof requestData !== "object") return;

    const status = String(requestData.status || "pending").trim().toLowerCase();
    if (status !== "pending") return;

    const senderName = String(
      data.name ||
      requestData.fromName ||
      (String(requestData.fromUid || "").trim() === docSnap.id ? requestData.name : "") ||
      "Usuario"
    ).trim() || "Usuario";
    const senderPhoto = String(
      data.photo ||
      requestData.fromPhoto ||
      (String(requestData.fromUid || "").trim() === docSnap.id ? requestData.photo : "") ||
      ""
    ).trim();
    const senderEmail = String(data.email || requestData.fromEmail || "").trim();

    const normalized = normalizeSocialUser(
      {
        uid: docSnap.id,
        name: senderName,
        email: senderEmail,
        photo: senderPhoto,
        requestedAt: requestData.requestedAt
      },
      docSnap.id
    );

    if (normalized) {
      remoteIncoming.push(normalized);
    }
  });

  acceptedSnapshot?.forEach((docSnap) => {
    if (!docSnap.exists()) return;
    if (docSnap.id === currentUser.uid) return;

    const data = docSnap.data() || {};
    friendLeaderboardDataByUid.set(docSnap.id, data);
    const acceptedMap = data?.[SOCIAL_ACCEPTED_FROM_FIELD];
    if (!acceptedMap || typeof acceptedMap !== "object") return;

    const acceptedData = acceptedMap[currentUser.uid];
    if (!acceptedData || typeof acceptedData !== "object") return;

    const acceptedAt = Math.max(0, Number(acceptedData.acceptedAt) || 0);
    const normalized = normalizeSocialUser(
      {
        uid: docSnap.id,
        name: data.name || acceptedData.name || "Usuario",
        photo: data.photo || acceptedData.photo || "",
        addedAt: acceptedAt
      },
      docSnap.id
    );

    if (normalized) {
      remoteFriends.push(normalized);
    }
  });

  const friendUidSet = new Set();
  socialState.localFriends.forEach((entry) => {
    const safeUid = String(entry?.uid || "").trim();
    if (!safeUid || safeUid === currentUser.uid) return;
    friendUidSet.add(safeUid);
  });
  remoteFriends.forEach((entry) => {
    const safeUid = String(entry?.uid || "").trim();
    if (!safeUid || safeUid === currentUser.uid) return;
    friendUidSet.add(safeUid);
  });

  const missingFriendUids = Array.from(friendUidSet).filter((uid) => !friendLeaderboardDataByUid.has(uid));
  if (missingFriendUids.length) {
    const uidChunks = [];
    for (let index = 0; index < missingFriendUids.length; index += 10) {
      uidChunks.push(missingFriendUids.slice(index, index + 10));
    }

    try {
      const friendSnapshots = await Promise.all(
        uidChunks.map((uids) => {
          return getDocs(
            query(
              collection(db, "leaderboard"),
              where(documentId(), "in", uids)
            )
          );
        })
      );

      if (runId !== socialState.remoteFetchToken) return;

      friendSnapshots.forEach((snapshot) => {
        snapshot.forEach((docSnap) => {
          if (!docSnap.exists()) return;
          if (docSnap.id === currentUser.uid) return;
          if (friendLeaderboardDataByUid.has(docSnap.id)) return;
          friendLeaderboardDataByUid.set(docSnap.id, docSnap.data() || {});
        });
      });
    } catch (err) {
      if (!isFirestorePermissionError(err)) {
        console.warn("No se pudieron leer chats de algunos amigos para contar no leídos.", err);
      }
    }
  }

  friendUidSet.forEach((friendUid) => {
    const friendData = friendLeaderboardDataByUid.get(friendUid);
    if (!friendData || typeof friendData !== "object") return;
    const readAt = Number(ownReadByUid.get(friendUid) || 0);
    const unreadCount = countUnreadSocialMessagesFromFriendDoc(
      friendUid,
      friendData,
      currentUser.uid,
      readAt
    );
    if (unreadCount > 0) {
      remoteUnreadByUid.set(friendUid, unreadCount);
    }
  });

  if (runId !== socialState.remoteFetchToken) return;

  socialState.remoteIncomingRequests = remoteIncoming;
  socialState.remoteFriends = remoteFriends;
  socialState.chatRemoteReadByUid = remoteReadByUid;
  socialState.chatOwnReadByUid = ownReadByUid;
  socialState.chatUnreadByUid = remoteUnreadByUid;
  writeSocialReadCache(ownReadByUid, currentUser.uid);
  ownReadByUid.forEach((value, peerUid) => {
    const safePeerUid = String(peerUid || "").trim();
    const timestamp = Math.max(0, Number(value) || 0);
    if (!safePeerUid || !timestamp) return;
    if (timestamp <= Number(remoteReadByUid.get(safePeerUid) || 0)) return;
    queueSocialReadReceipt(safePeerUid, timestamp);
  });
  syncSocialActiveChatUnreadCount();
  socialState.remoteFetchedAt = Date.now();
  combineSocialCollections();
  patchSocialRequestsUI();
  patchSocialSearchResultsUI();
  patchSocialFriendsUI();
  if (isPlayerReadyForAchievementChecks()) {
    checkAchievements({ silent: false });
  }
}

function formatSocialTimestamp(value){
  const timestamp = Math.max(0, Number(value) || 0);
  if (!timestamp) return "Reciente";

  try {
    const date = new Date(timestamp);
    if (Number.isNaN(date.getTime())) return "Reciente";
    const day = String(date.getDate()).padStart(2, "0");
    const month = String(date.getMonth() + 1).padStart(2, "0");
    const hours = String(date.getHours()).padStart(2, "0");
    const minutes = String(date.getMinutes()).padStart(2, "0");
    return `${day}/${month}, ${hours}:${minutes}`;
  } catch (_error) {
    return "Reciente";
  }
}

function getSocialSearchResults(rawQuery = "", users = []){
  const queryText = normalizeTextForSearch(rawQuery);
  if (!queryText) return [];
  if (!Array.isArray(users) || !users.length) return [];

  const results = users.filter((user) => {
    if (!user?.uid || user.uid === currentUser?.uid) return false;
    const userNameSearch = String(user.nameSearch || normalizeTextForSearch(user.name || ""));
    return userNameSearch.includes(queryText);
  });

  results.sort((a, b) => {
    const aNameStarts = String(a.nameSearch || normalizeTextForSearch(a.name || "")).startsWith(queryText);
    const bNameStarts = String(b.nameSearch || normalizeTextForSearch(b.name || "")).startsWith(queryText);
    if (aNameStarts !== bNameStarts) return aNameStarts ? -1 : 1;

    return String(a.name || "").localeCompare(String(b.name || ""), "es", { sensitivity: "base" });
  });

  return results.slice(0, SOCIAL_SEARCH_MAX_RESULTS);
}

async function loadSocialDirectoryFromUsersCollection(){
  const users = [];
  const snapshot = await getDocs(collection(db, "users"));

  snapshot.forEach((docSnap) => {
    const data = docSnap.data() || {};
    const normalized = normalizeSocialUser(
      {
        uid: docSnap.id,
        name: data.name || data.displayName || "Usuario",
        email: data.email || "",
        photo: data.photo || data.photoURL || ""
      },
      docSnap.id
    );

    if (normalized) {
      users.push(normalized);
    }
  });

  return users;
}

async function loadSocialDirectoryFromLeaderboard(){
  const users = [];
  const leaderboardQuery = query(
    collection(db, "leaderboard"),
    orderBy("name", "asc"),
    limit(300)
  );
  const snapshot = await getDocs(leaderboardQuery);

  snapshot.forEach((docSnap) => {
    const data = docSnap.data() || {};
    const normalized = normalizeSocialUser(
      {
        uid: docSnap.id,
        name: data.name || "Usuario",
        email: data.email || "",
        photo: data.photo || ""
      },
      docSnap.id
    );

    if (normalized) {
      users.push(normalized);
    }
  });

  return users;
}

async function loadSocialDirectoryUsers({ force = false } = {}){
  const now = Date.now();
  const cacheIsFresh =
    !force &&
    socialState.directoryFetchedAt > 0 &&
    (now - socialState.directoryFetchedAt) < SOCIAL_DIRECTORY_CACHE_TTL_MS &&
    socialState.directoryUsers.length > 0;

  if (cacheIsFresh) {
    return socialState.directoryUsers;
  }

  let users = [];
  socialState.searchError = "";

  try {
    users = await loadSocialDirectoryFromUsersCollection();
  } catch (err) {
    if (!isFirestorePermissionError(err)) {
      throw err;
    }

    users = await loadSocialDirectoryFromLeaderboard();
  }

  const uniqueUsers = [];
  const seen = new Set();

  users.forEach((entry) => {
    const uid = String(entry?.uid || "").trim();
    if (!uid || seen.has(uid)) return;
    seen.add(uid);
    uniqueUsers.push(entry);
  });

  socialState.directoryUsers = uniqueUsers;
  socialState.directoryFetchedAt = Date.now();
  return uniqueUsers;
}

async function runSocialSearch(queryText){
  const normalizedQuery = String(queryText || "").trim();
  socialState.searchQuery = normalizedQuery;
  const runId = ++socialState.searchToken;

  if (!normalizedQuery) {
    socialState.searchLoading = false;
    socialState.searchError = "";
    socialState.searchResults = [];
    if (currentViewMode === VIEW_MODE_SOCIAL) {
      patchSocialSearchResultsUI();
    }
    return;
  }

  if (normalizedQuery.includes("@")) {
    socialState.searchLoading = false;
    socialState.searchError = "La búsqueda social solo está disponible por nombre de usuario.";
    socialState.searchResults = [];
    if (currentViewMode === VIEW_MODE_SOCIAL) {
      patchSocialSearchResultsUI();
    }
    return;
  }

  socialState.searchLoading = true;
  socialState.searchResults = [];
  if (currentViewMode === VIEW_MODE_SOCIAL) {
    patchSocialSearchResultsUI();
  }

  try {
    const users = await loadSocialDirectoryUsers();
    if (runId !== socialState.searchToken) return;
    socialState.searchResults = getSocialSearchResults(normalizedQuery, users);
  } catch (err) {
    if (runId !== socialState.searchToken) return;
    socialState.searchError = "No se pudo completar la búsqueda en este momento.";
    socialState.searchResults = [];
    console.error("No se pudo cargar directorio social.", err);
  } finally {
    if (runId !== socialState.searchToken) return;
    socialState.searchLoading = false;
    if (currentViewMode === VIEW_MODE_SOCIAL) {
      patchSocialSearchResultsUI();
    }
  }
}

async function sendSocialFriendRequest(targetUser = {}){
  const target = normalizeSocialUser(targetUser, targetUser?.uid);
  const requester = getCurrentUserSocialIdentity();

  if (!target?.uid) {
    showToast("No se pudo identificar al usuario.");
    return false;
  }

  if (!requester?.uid) {
    showToast("Iniciá sesión para enviar solicitudes.");
    return false;
  }

  if (target.uid === requester.uid) {
    showToast("No podés enviarte una solicitud a vos.");
    return false;
  }

  if (socialState.friendsByUid.has(target.uid)) {
    showToast(`Ya sos amigo de ${target.name}.`);
    return false;
  }

  const now = Date.now();
  const requestPayload = {
    uid: requester.uid,
    name: requester.name,
    email: requester.email,
    photo: requester.photo,
    requestedAt: now,
    status: "pending"
  };
  const outgoingPayload = {
    uid: target.uid,
    name: target.name,
    photo: target.photo,
    fromUid: requester.uid,
    fromName: requester.name,
    fromEmail: requester.email,
    fromPhoto: requester.photo,
    requestedAt: now,
    status: "pending"
  };

  try {
    await setDoc(
      doc(db, "users", target.uid),
      {
        [SOCIAL_INCOMING_REQUESTS_FIELD]: {
          [requester.uid]: requestPayload
        }
      },
      { merge: true }
    );
  } catch (err) {
    if (!isFirestorePermissionError(err)) {
      throw err;
    }

    await setDoc(
      doc(db, "leaderboard", requester.uid),
      {
        [SOCIAL_OUTGOING_REQUESTS_FIELD]: {
          [target.uid]: outgoingPayload
        }
      },
      { merge: true }
    );
  }

  try {
    await setDoc(
      doc(db, "users", requester.uid),
      {
        [SOCIAL_OUTGOING_REQUESTS_FIELD]: {
          [target.uid]: outgoingPayload
        }
      },
      { merge: true }
    );
  } catch (err) {
    if (!isFirestorePermissionError(err)) {
      console.warn("No se pudo persistir estado local de solicitud social.", err);
    }
  }

  const withoutTarget = socialState.localOutgoingRequests.filter((entry) => entry.uid !== target.uid);
  const normalizedOutgoing = normalizeSocialUser(
    {
      uid: target.uid,
      name: target.name,
      photo: target.photo,
      requestedAt: now
    },
    target.uid
  );
  if (normalizedOutgoing) {
    withoutTarget.push({
      ...normalizedOutgoing,
      status: "pending"
    });
  }
  socialState.localOutgoingRequests = withoutTarget;
  combineSocialCollections();

  socialState.remoteFetchedAt = 0;
  void refreshSocialRemoteState({ force: true });
  patchSocialRequestsUI();
  patchSocialSearchResultsUI();
  showToast(`Solicitud enviada a ${target.name}.`);
  return true;
}

async function rejectSocialFriendRequest(fromUid){
  const safeUid = String(fromUid || "").trim();
  if (!safeUid || !currentUser?.uid) {
    showToast("No se pudo rechazar la solicitud.");
    return false;
  }

  const rejectedAt = Date.now();
  await updateDoc(doc(db, "users", currentUser.uid), {
    [`${SOCIAL_INCOMING_REQUESTS_FIELD}.${safeUid}`]: deleteField(),
    [`${SOCIAL_REJECTED_REQUESTS_FIELD}.${safeUid}`]: rejectedAt
  });

  socialState.localIncomingRequests = socialState.localIncomingRequests.filter((entry) => entry.uid !== safeUid);
  socialState.rejectedByUid.set(safeUid, rejectedAt);
  combineSocialCollections();
  patchSocialRequestsUI();
  patchSocialSearchResultsUI();

  socialState.remoteFetchedAt = 0;
  void refreshSocialRemoteState({ force: true });
  return true;
}

async function acceptSocialFriendRequest(fromUid){
  const safeUid = String(fromUid || "").trim();
  if (!safeUid || !currentUser?.uid) {
    showToast("No se pudo aceptar la solicitud.");
    return false;
  }

  const incomingUser = socialState.incomingByUid.get(safeUid);
  if (!incomingUser) {
    showToast("La solicitud ya no está disponible.");
    return false;
  }

  const currentIdentity = getCurrentUserSocialIdentity();
  if (!currentIdentity) {
    showToast("Iniciá sesión para aceptar solicitudes.");
    return false;
  }

  const now = Date.now();
  const friendForCurrentUser = {
    uid: incomingUser.uid,
    name: incomingUser.name,
    email: incomingUser.email,
    photo: incomingUser.photo,
    addedAt: now
  };
  const friendForSender = {
    uid: currentIdentity.uid,
    name: currentIdentity.name,
    email: currentIdentity.email,
    photo: currentIdentity.photo,
    addedAt: now
  };

  try {
    const batch = writeBatch(db);
    const currentUserRef = doc(db, "users", currentIdentity.uid);
    const senderRef = doc(db, "users", incomingUser.uid);

    batch.update(currentUserRef, {
      [`${SOCIAL_INCOMING_REQUESTS_FIELD}.${incomingUser.uid}`]: deleteField(),
      [`${SOCIAL_REJECTED_REQUESTS_FIELD}.${incomingUser.uid}`]: deleteField(),
      [`${SOCIAL_FRIENDS_FIELD}.${incomingUser.uid}`]: friendForCurrentUser
    });

    batch.update(senderRef, {
      [`${SOCIAL_INCOMING_REQUESTS_FIELD}.${currentIdentity.uid}`]: deleteField(),
      [`${SOCIAL_FRIENDS_FIELD}.${currentIdentity.uid}`]: friendForSender
    });

    await batch.commit();
  } catch (err) {
    if (!isFirestorePermissionError(err)) {
      throw err;
    }

    await updateDoc(doc(db, "users", currentIdentity.uid), {
      [`${SOCIAL_INCOMING_REQUESTS_FIELD}.${incomingUser.uid}`]: deleteField(),
      [`${SOCIAL_REJECTED_REQUESTS_FIELD}.${incomingUser.uid}`]: deleteField(),
      [`${SOCIAL_FRIENDS_FIELD}.${incomingUser.uid}`]: friendForCurrentUser
    });

    await setDoc(
      doc(db, "leaderboard", currentIdentity.uid),
      {
        [SOCIAL_ACCEPTED_FROM_FIELD]: {
          [incomingUser.uid]: {
            uid: incomingUser.uid,
            name: incomingUser.name,
            photo: incomingUser.photo,
            acceptedAt: now
          }
        },
        [SOCIAL_ACCEPTED_FLAGS_FIELD]: {
          [incomingUser.uid]: true
        }
      },
      { merge: true }
    );
  }

  socialState.remoteFetchedAt = 0;
  socialState.localIncomingRequests = socialState.localIncomingRequests.filter((entry) => entry.uid !== incomingUser.uid);
  socialState.localOutgoingRequests = socialState.localOutgoingRequests.filter((entry) => entry.uid !== incomingUser.uid);
  socialState.rejectedByUid.delete(incomingUser.uid);
  if (!socialState.localFriends.some((entry) => entry.uid === incomingUser.uid)) {
    const normalizedFriend = normalizeSocialUser(
      {
        uid: incomingUser.uid,
        name: incomingUser.name,
        photo: incomingUser.photo,
        addedAt: now
      },
      incomingUser.uid
    );
    if (normalizedFriend) {
      socialState.localFriends.push(normalizedFriend);
    }
  }
  combineSocialCollections();
  patchSocialRequestsUI();
  patchSocialSearchResultsUI();
  patchSocialFriendsUI();
  void refreshSocialRemoteState({ force: true });
  showToast(`Ahora ${incomingUser.name} y vos son amigos.`);
  return true;
}

function formatLeaderboardDate(value){
  const safeValue = String(value || "").trim();
  if (!safeValue) return "Sin registro";
  const parsed = new Date(`${safeValue}T00:00:00`);
  if (Number.isNaN(parsed.getTime())) return safeValue;
  return parsed.toLocaleDateString("es-AR");
}

function hasLeaderboardDetailedFields(user = {}){
  if (user?.playerData && typeof user.playerData === "object") return true;

  const detailedKeys = [
    "activeStreak",
    "longestStreak",
    "allTasksStreak",
    "completedTasks",
    "totalFocusMinutes",
    "todayExpTasks",
    "achievementsUnlocked",
    "lastActiveDate",
    "lastAllTasksDate",
    "lastExpDate",
    "updatedAt"
  ];

  return detailedKeys.some((key) => Object.prototype.hasOwnProperty.call(user, key));
}

function hasLeaderboardProgress(user = {}){
  return (
    Math.max(0, Number(user.level) || 0) > 0 ||
    Math.max(0, Number(user.exp) || 0) > 0 ||
    Math.max(0, Number(user.completedTasks) || 0) > 0 ||
    Math.max(0, Number(user.activeStreak) || 0) > 0 ||
    Math.max(0, Number(user.longestStreak) || 0) > 0 ||
    Math.max(0, Number(user.allTasksStreak) || 0) > 0 ||
    Math.max(0, Number(user.totalFocusMinutes) || 0) > 0 ||
    Math.max(0, Number(user.todayExpTasks) || 0) > 0 ||
    Math.max(0, Number(user.achievementsUnlocked) || 0) > 0 ||
    !!String(user.lastActiveDate || "").trim() ||
    !!String(user.lastAllTasksDate || "").trim() ||
    !!String(user.lastExpDate || "").trim()
  );
}

function isPlaceholderLeaderboardEntry(user = {}){
  const name = String(user.name || "").trim().toLowerCase();
  const hasPhoto = !!String(user.photo || "").trim();
  const hasProgress = hasLeaderboardProgress(user);
  const anonymousName = !name || name === "usuario";

  return anonymousName && !hasPhoto && !hasProgress;
}

function getLeaderboardPublicSummary(user = {}){
  return {
    uid: String(user.uid || ""),
    name: String(user.name || "Usuario"),
    photo: String(user.photo || ""),
    level: Math.max(0, Number(user.level) || 0),
    exp: Math.max(0, Number(user.exp) || 0),
    completedTasks: Math.max(0, Number(user.completedTasks) || 0),
    activeStreak: Math.max(0, Number(user.activeStreak) || 0),
    longestStreak: Math.max(0, Number(user.longestStreak) || 0),
    allTasksStreak: Math.max(0, Number(user.allTasksStreak) || 0),
    totalFocusMinutes: Math.max(0, Number(user.totalFocusMinutes) || 0),
    todayExpTasks: Math.max(0, Number(user.todayExpTasks) || 0),
    achievementsUnlocked: Math.max(0, Number(user.achievementsUnlocked) || 0),
    lastActiveDate: user.lastActiveDate || null,
    lastAllTasksDate: user.lastAllTasksDate || null,
    lastExpDate: user.lastExpDate || null,
    updatedAt: Math.max(0, Number(user.updatedAt) || 0),
    playerData: user?.playerData && typeof user.playerData === "object" ? user.playerData : null,
    hasDetailedStats: hasLeaderboardDetailedFields(user)
  };
}

function getLeaderboardDetailedSummary(playerData = {}, baseUser = {}){
  const safePlayer = normalizePlayer(playerData || {});
  const summary = getLeaderboardPublicSummary(baseUser);
  const levelFromPlayer = Math.max(0, Number(safePlayer.level) || 0);
  const expFromPlayer = Math.max(0, Number(safePlayer.exp) || 0);
  const completedFromPlayer = Math.max(0, Number(safePlayer.totalCompletedTasks) || 0);

  return {
    ...summary,
    level: Math.max(summary.level, levelFromPlayer),
    exp: Math.max(summary.exp, expFromPlayer),
    completedTasks: Math.max(0, Number(summary.completedTasks) || 0, completedFromPlayer),
    activeStreak: Math.max(0, Number(safePlayer.activeStreak) || 0),
    longestStreak: Math.max(0, Number(safePlayer.longestStreak) || 0),
    allTasksStreak: Math.max(0, Number(safePlayer.allTasksStreak) || 0),
    totalFocusMinutes: Math.max(0, Number(safePlayer.totalFocusMinutes) || 0),
    todayExpTasks: Math.max(0, Number(safePlayer.todayExpTasks) || 0),
    achievementsUnlocked: Math.max(0, Number(Object.keys(safePlayer.achievements || {}).length) || 0),
    lastActiveDate: safePlayer.lastActiveDate || summary.lastActiveDate || null,
    lastAllTasksDate: safePlayer.lastAllTasksDate || summary.lastAllTasksDate || null,
    lastExpDate: safePlayer.lastExpDate || summary.lastExpDate || null,
    updatedAt: Math.max(summary.updatedAt, Number(safePlayer.updatedAt) || 0),
    playerData: safePlayer,
    hasDetailedStats: true
  };
}

function renderLeaderboardAddFriendButton(summary = {}, { loading = false } = {}){
  const safeSummary = getLeaderboardPublicSummary(summary);
  const safeUid = String(safeSummary.uid || "");
  const safeName = String(safeSummary.name || "Usuario");
  const isSelfProfile = !!currentUser?.uid && safeUid === currentUser.uid;
  if (isSelfProfile || !safeUid) {
    return "";
  }

  const isOutgoingPending =
    !loading &&
    socialState.outgoingPendingByUid instanceof Map &&
    socialState.outgoingPendingByUid.has(safeUid);
  const isAlreadyFriend =
    !loading &&
    socialState.friendsByUid instanceof Map &&
    socialState.friendsByUid.has(safeUid);

  if (isAlreadyFriend) {
    return `
      <div class="leaderboard-profile-add-friend-wrap">
        <button
          class="leaderboard-profile-add-friend-btn sent"
          type="button"
          aria-label="Ya son amigos"
          disabled
        >
          <svg viewBox="0 0 24 24" fill="none" aria-hidden="true">
            <path d="M5.5 12.5 10 17l8.5-8.5" stroke="currentColor" stroke-width="2.3" stroke-linecap="round" stroke-linejoin="round"></path>
          </svg>
          <span>Amigos</span>
        </button>
      </div>
    `;
  }

  if (isOutgoingPending) {
    return `
      <div class="leaderboard-profile-add-friend-wrap">
        <button
          class="leaderboard-profile-add-friend-btn sent"
          type="button"
          aria-label="Solicitud enviada a ${escapeHtml(safeName)}"
          disabled
        >
          <svg viewBox="0 0 24 24" fill="none" aria-hidden="true">
            <path d="M5.5 12.5 10 17l8.5-8.5" stroke="currentColor" stroke-width="2.3" stroke-linecap="round" stroke-linejoin="round"></path>
          </svg>
          <span>Solicitud enviada</span>
        </button>
      </div>
    `;
  }

  const shouldDisable = loading;
  const buttonLabel = loading ? "Preparando..." : "Agregar amigo";
  const buttonAriaLabel = `Agregar a ${safeName} como amigo`;

  return `
    <div class="leaderboard-profile-add-friend-wrap">
      <button
        class="leaderboard-profile-add-friend-btn"
        type="button"
        data-leaderboard-add-friend-btn
        data-leaderboard-user-uid="${escapeHtml(safeUid)}"
        data-leaderboard-user-name="${escapeHtml(safeName)}"
        aria-label="${escapeHtml(buttonAriaLabel)}"
        ${shouldDisable ? "disabled" : ""}
      >
        <svg viewBox="0 0 24 24" fill="none" aria-hidden="true">
          <circle cx="8.8" cy="8" r="3.2" stroke="currentColor" stroke-width="2"></circle>
          <path d="M3.8 18.3a5.9 5.9 0 0 1 10 0" stroke="currentColor" stroke-width="2" stroke-linecap="round"></path>
          <path d="M18 10v6" stroke="currentColor" stroke-width="2.2" stroke-linecap="round"></path>
          <path d="M15 13h6" stroke="currentColor" stroke-width="2.2" stroke-linecap="round"></path>
        </svg>
        <span>${escapeHtml(buttonLabel)}</span>
      </button>
    </div>
  `;
}

function renderLeaderboardProfileMenu(summary = {}, { loading = false } = {}){
  const safeSummary = getLeaderboardPublicSummary(summary);
  const safeName = String(safeSummary.name || "Usuario");
  const safePhoto = String(safeSummary.photo || "");
  const avatarSrc = safePhoto || getLeaderboardFallbackPhoto(safeName);
  const fallbackAvatar = getLeaderboardFallbackPhoto(safeName);
  const safeNameHtml = escapeHtml(safeName);
  const safeAvatarHtml = escapeHtml(avatarSrc);
  const safeFallbackAvatarHtml = escapeHtml(fallbackAvatar);

  if (loading) {
    return `
      <div class="leaderboard-profile-header">
        <img
          class="leaderboard-profile-photo"
          src="${safeAvatarHtml}"
          alt="Foto de ${safeNameHtml}"
          onerror="this.src='${safeFallbackAvatarHtml}'"
        >
        <div class="leaderboard-profile-header-copy">
          <div class="leaderboard-profile-name">${safeNameHtml}</div>
          <div class="leaderboard-profile-subtitle">Perfil</div>
        </div>
      </div>
      <div class="leaderboard-profile-loading">Cargando perfil...</div>
      ${renderLeaderboardAddFriendButton(safeSummary, { loading: true })}
    `;
  }

  const completedTasksValue = Math.max(0, Number(safeSummary.completedTasks) || 0);

  const stats = [
    { label: "Nivel", value: formatSettingsStat(safeSummary.level) },
    { label: "EXP total", value: `${formatSettingsStat(safeSummary.exp)} pts` },
    { label: "Total de tareas completadas", value: formatSettingsStat(completedTasksValue) },
    {
      label: "Minutos en sesiones de enfoque",
      value: `${formatSettingsStat(safeSummary.totalFocusMinutes)} min`
    },
    { label: "Racha activa", value: `${formatSettingsStat(safeSummary.activeStreak)} días` },
    { label: "Mejor racha", value: `${formatSettingsStat(safeSummary.longestStreak)} días` },
    { label: "Logros desbloqueados", value: formatSettingsStat(safeSummary.achievementsUnlocked) },
    { label: "Último día activo", value: formatLeaderboardDate(safeSummary.lastActiveDate) }
  ];

  const statsHtml = stats.map((stat) => `
    <div class="leaderboard-profile-stat">
      <span class="leaderboard-profile-stat-label">${escapeHtml(stat.label)}</span>
      <span class="leaderboard-profile-stat-value">${escapeHtml(stat.value)}</span>
    </div>
  `).join("");

  return `
    <div class="leaderboard-profile-header">
      <img
        class="leaderboard-profile-photo"
        src="${safeAvatarHtml}"
        alt="Foto de ${safeNameHtml}"
        onerror="this.src='${safeFallbackAvatarHtml}'"
      >
      <div class="leaderboard-profile-header-copy">
        <div class="leaderboard-profile-name">${safeNameHtml}</div>
        <div class="leaderboard-profile-subtitle">Perfil</div>
      </div>
    </div>
    <div class="leaderboard-profile-stats">${statsHtml}</div>
    ${renderLeaderboardAddFriendButton(safeSummary)}
  `;
}

async function fetchLeaderboardProfileSummary(user){
  const publicSummary = getLeaderboardPublicSummary(user);
  if (!publicSummary.uid) return publicSummary;

  if (leaderboardProfileCache.has(publicSummary.uid)) {
    return leaderboardProfileCache.get(publicSummary.uid);
  }

  if (publicSummary.playerData) {
    const summaryFromLeaderboardDoc = getLeaderboardDetailedSummary(
      publicSummary.playerData,
      publicSummary
    );
    leaderboardProfileCache.set(publicSummary.uid, summaryFromLeaderboardDoc);
    return summaryFromLeaderboardDoc;
  }

  if (currentUser?.uid === publicSummary.uid) {
    const localSummary = getLeaderboardDetailedSummary(player, publicSummary);
    leaderboardProfileCache.set(publicSummary.uid, localSummary);
    return localSummary;
  }

  try {
    const remoteProfileSnap = await getDoc(doc(db, "leaderboard", publicSummary.uid));
    if (remoteProfileSnap.exists()) {
      const remoteData = remoteProfileSnap.data() || {};
      const remotePlayer =
        remoteData?.player && typeof remoteData.player === "object" ? remoteData.player : null;

      const remoteSummary = getLeaderboardPublicSummary({
        uid: publicSummary.uid,
        name: String(remoteData.name || publicSummary.name || "Usuario"),
        photo: String(remoteData.photo || publicSummary.photo || ""),
        level: remoteData.level,
        exp: remoteData.exp,
        completedTasks: remoteData.completedTasks,
        activeStreak: remoteData.activeStreak,
        longestStreak: remoteData.longestStreak,
        allTasksStreak: remoteData.allTasksStreak,
        totalFocusMinutes: remoteData.totalFocusMinutes,
        todayExpTasks: remoteData.todayExpTasks,
        achievementsUnlocked: remoteData.achievementsUnlocked,
        lastActiveDate: remoteData.lastActiveDate,
        lastAllTasksDate: remoteData.lastAllTasksDate,
        lastExpDate: remoteData.lastExpDate,
        updatedAt: remoteData.updatedAt,
        playerData: remotePlayer
      });

      const summaryFromRemote = remotePlayer
        ? getLeaderboardDetailedSummary(remotePlayer, remoteSummary)
        : remoteSummary;

      leaderboardProfileCache.set(publicSummary.uid, summaryFromRemote);
      return summaryFromRemote;
    }
  } catch (err) {
    if (!isFirestorePermissionError(err)) {
      console.warn("No se pudo cargar el perfil remoto del leaderboard.", err);
    }
  }

  leaderboardProfileCache.set(publicSummary.uid, publicSummary);
  return publicSummary;
}

function showLeaderboardModal(users){

  const existing = document.getElementById("leaderboardOverlay");
  if(existing) existing.remove();

  const overlay = document.createElement("div");
  overlay.className = "overlay open";
  overlay.id = "leaderboardOverlay";

  const stage = document.createElement("div");
  stage.className = "leaderboard-stage";

  const modal = document.createElement("div");
  modal.className = "modal leaderboard-modal";

  let html = `
    <div class="mhead">
      <strong>TABLA DE POSICIONES</strong>
      <button class="btn" id="closeLeaderboard">Cerrar</button>
    </div>
    <div class="mbody leaderboard-list">
  `;

  if(users.length === 0){
    html += `<div class="leaderboard-empty">Aún no hay jugadores</div>`;
  }

  users.forEach((u,i)=>{
    const safeUid = String(u.uid || "");
    const safeName = String(u.name || "Usuario");
    const safePhoto = String(u.photo || "");
    const safeLevel = Math.max(0, Number(u.level) || 0);
    const safeExp = Math.max(0, Number(u.exp) || 0);
    const escapedUid = escapeHtml(safeUid);
    const escapedName = escapeHtml(safeName);
    const escapedPhoto = escapeHtml(safePhoto || getLeaderboardFallbackPhoto(safeName));
    const escapedFallbackPhoto = escapeHtml(getLeaderboardFallbackPhoto(safeName));
    const escapedAria = escapeHtml(`Ver resumen de ${safeName}`);

    let posDisplay;

    if(i === 0) posDisplay = "🥇";
    else if(i === 1) posDisplay = "🥈";
    else if(i === 2) posDisplay = "🥉";
    else posDisplay = `<span class="leader-rank-circle">${i+1}</span>`;

    html += `
      <div
        class="leaderboard-row ${currentUser && safeUid === currentUser.uid ? "leader-self" : ""}"
        data-leader-uid="${escapedUid}"
        role="button"
        tabindex="0"
        aria-expanded="false"
        aria-label="${escapedAria}"
      >
        <div class="leader-pos">${posDisplay}</div>
        <img
          class="leader-photo"
          src="${escapedPhoto}"
          alt="Foto de ${escapedName}"
          onerror="this.src='${escapedFallbackPhoto}'"
        >
        <div class="leader-name">${escapedName}</div>
        <div class="leader-level">Nivel ${formatSettingsStat(safeLevel)}</div>
        <div class="leader-exp">${formatSettingsStat(safeExp)} pts</div>
      </div>
    `;
  });

  html += `</div>`;

  modal.innerHTML = html;

  const leaderboardProfileDrawer = document.createElement("aside");
  leaderboardProfileDrawer.className = "leaderboard-profile-drawer";
  leaderboardProfileDrawer.setAttribute("aria-hidden", "true");
  leaderboardProfileDrawer.innerHTML = `
    <div class="leaderboard-profile-mobile-head">
      <button
        type="button"
        class="leaderboard-profile-mobile-back"
        data-leaderboard-profile-back
        aria-label="Volver a la tabla de posiciones"
      >
        <svg viewBox="0 0 24 24" fill="none" aria-hidden="true">
          <path d="M15 18 9 12l6-6" stroke="currentColor" stroke-width="2.1" stroke-linecap="round" stroke-linejoin="round"></path>
        </svg>
        <span>Volver</span>
      </button>
      <strong>Perfil</strong>
    </div>
    <div class="leaderboard-profile-panel-content">
      <div class="leaderboard-profile-empty">Tocá una fila para ver el perfil completo.</div>
    </div>
  `;

  stage.appendChild(modal);
  stage.appendChild(leaderboardProfileDrawer);
  overlay.appendChild(stage);
  document.body.appendChild(overlay);

  const leaderboardList = modal.querySelector(".leaderboard-list");
  const leaderboardProfileContent = leaderboardProfileDrawer.querySelector(".leaderboard-profile-panel-content");
  const leaderboardProfileBackBtn = leaderboardProfileDrawer.querySelector("[data-leaderboard-profile-back]");
  const usersByUid = new Map(
    users.map((user) => [String(user.uid || ""), getLeaderboardPublicSummary(user)])
  );
  let activeProfileUid = "";

  const resetEmptyProfile = () => {
    if (!leaderboardProfileContent) return;
    leaderboardProfileContent.innerHTML =
      `<div class="leaderboard-profile-empty">Tocá una fila para ver el perfil completo.</div>`;
  };

  const setActiveRowState = (uid = "") => {
    leaderboardList?.querySelectorAll(".leaderboard-row[data-leader-uid]").forEach((rowElement) => {
      const isActive = !!uid && String(rowElement.dataset.leaderUid || "") === uid;
      rowElement.classList.toggle("leader-open", isActive);
      rowElement.setAttribute("aria-expanded", isActive ? "true" : "false");
    });
  };

  const closeProfilePanel = () => {
    activeProfileUid = "";
    stage.classList.remove("profile-open");
    leaderboardProfileDrawer.setAttribute("aria-hidden", "true");
    setActiveRowState("");
    resetEmptyProfile();
  };

  leaderboardProfileBackBtn?.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    closeProfilePanel();
  });

  leaderboardList?.querySelectorAll(".leaderboard-row[data-leader-uid]").forEach((rowElement) => {
    const uid = String(rowElement.dataset.leaderUid || "");
    const user = usersByUid.get(uid);
    if (!user) return;

    const activate = async () => {
      if (!leaderboardProfileContent) return;

      const isSameProfileOpen =
        activeProfileUid === uid &&
        stage.classList.contains("profile-open");

      if (isSameProfileOpen) {
        closeProfilePanel();
        return;
      }

      activeProfileUid = uid;
      stage.classList.add("profile-open");
      leaderboardProfileDrawer.setAttribute("aria-hidden", "false");
      setActiveRowState(uid);
      leaderboardProfileContent.innerHTML = renderLeaderboardProfileMenu(user, { loading: true });

      const requestedUid = uid;
      const summary = await fetchLeaderboardProfileSummary(user);

      if (activeProfileUid !== requestedUid) return;
      if (!leaderboardProfileContent.isConnected) return;

      leaderboardProfileContent.innerHTML = renderLeaderboardProfileMenu(summary);
    };

    rowElement.addEventListener("click", activate);
    rowElement.addEventListener("keydown", (event) => {
      if (event.key !== "Enter" && event.key !== " ") return;
      event.preventDefault();
      activate();
    });
  });

  leaderboardProfileContent?.addEventListener("click", async (event) => {
    if (!(event.target instanceof Element)) return;
    const addFriendBtn = event.target.closest("[data-leaderboard-add-friend-btn]");
    if (!addFriendBtn) return;

    event.preventDefault();
    event.stopPropagation();

    const targetUid = String(addFriendBtn.dataset.leaderboardUserUid || "").trim();
    const targetName = String(addFriendBtn.dataset.leaderboardUserName || "Usuario").trim() || "Usuario";

    try {
      const requestSent = await sendSocialFriendRequest({
        uid: targetUid,
        name: targetName
      });

      if (requestSent && addFriendBtn instanceof HTMLButtonElement) {
        addFriendBtn.classList.add("sent");
        addFriendBtn.disabled = true;
        addFriendBtn.removeAttribute("data-leaderboard-add-friend-btn");
        addFriendBtn.removeAttribute("data-leaderboard-user-uid");
        addFriendBtn.removeAttribute("data-leaderboard-user-name");
        addFriendBtn.setAttribute("aria-label", `Solicitud enviada a ${targetName}`);
        addFriendBtn.innerHTML = `
          <svg viewBox="0 0 24 24" fill="none" aria-hidden="true">
            <path d="M5.5 12.5 10 17l8.5-8.5" stroke="currentColor" stroke-width="2.3" stroke-linecap="round" stroke-linejoin="round"></path>
          </svg>
          <span>Solicitud enviada</span>
        `;
      }
    } catch (err) {
      console.error("No se pudo enviar solicitud desde leaderboard.", err);
      if (isFirestorePermissionError(err)) {
        showToast("No hay permisos suficientes para enviar solicitudes.");
      } else {
        showToast("No se pudo enviar la solicitud de amistad.");
      }
    }
  });

  document
    .getElementById("closeLeaderboard")
    .onclick = ()=>{
      closeProfilePanel();
      overlay.remove();

      if(leaderboardUnsub){
        leaderboardUnsub();
        leaderboardUnsub = null;
      }
    };

  overlay.onclick = (e)=>{
    if(e.target === overlay){
      closeProfilePanel();
      overlay.remove();

      if(leaderboardUnsub){
        leaderboardUnsub();
        leaderboardUnsub = null;
      }
    }
  };

}

let profileMenuOpen = false;
const cornerContainer = document.getElementById("cornerContainer");

cornerContainer?.classList.add("collapsed");

function stopDashboardProfileTriggerResizeObserver(){
  if (!dashboardProfileTriggerResizeObserver) return;
  dashboardProfileTriggerResizeObserver.disconnect();
  dashboardProfileTriggerResizeObserver = null;
}

function watchDashboardProfileTriggerSize(trigger){
  stopDashboardProfileTriggerResizeObserver();
  if (typeof ResizeObserver !== "function" || !trigger) return;

  dashboardProfileTriggerResizeObserver = new ResizeObserver(() => {
    const isDashboardMenuOpen =
      profileMenuOpen &&
      cornerContainer?.classList.contains("dashboard-pill-mode") &&
      activeDashboardProfileTrigger === trigger;
    if (!isDashboardMenuOpen) return;
    positionCornerMenuFromDashboardPill(trigger);
  });
  dashboardProfileTriggerResizeObserver.observe(trigger);
}

function closeCornerMenu() {
  if(!cornerContainer) return;

  cornerContainer.classList.remove("expanded", "closing");
  cornerContainer.classList.add("collapsed");
  cornerContainer.classList.remove("dashboard-pill-mode");
  cornerContainer.style.removeProperty("top");
  cornerContainer.style.removeProperty("right");
  cornerContainer.style.removeProperty("left");
  cornerContainer.style.removeProperty("width");
  stopDashboardProfileTriggerResizeObserver();
  document.body.classList.remove("dashboard-profile-menu-open");
  if (activeDashboardProfileTrigger) {
    activeDashboardProfileTrigger.classList.remove("menu-open");
    activeDashboardProfileTrigger.setAttribute("aria-expanded", "false");
  }
  activeDashboardProfileTrigger = null;
  loginCircleBtn?.setAttribute("aria-expanded", "false");

  profileMenuOpen = false;
}

function openCornerMenu() {
  if(!cornerContainer) return;

  cornerContainer.classList.remove("collapsed");
  cornerContainer.classList.add("expanded");
  loginCircleBtn?.setAttribute("aria-expanded", "true");

  profileMenuOpen = true;
}

function positionCornerMenuFromDashboardPill(trigger){
  if(!trigger || !cornerContainer) return;
  const rect = trigger.getBoundingClientRect();
  const viewportPadding = window.innerWidth <= MOBILE_BREAKPOINT ? 10 : 12;
  const maxViewportWidth = Math.max(0, Math.round(window.innerWidth - (viewportPadding * 2)));
  const triggerWidth = Math.max(1, Math.round(rect.width));
  const preferredWidth = Math.min(triggerWidth, maxViewportWidth);
  const preferredLeft = Math.round(rect.left);
  const leftMin = viewportPadding;
  const leftMax = Math.max(
    leftMin,
    Math.round(window.innerWidth - preferredWidth - viewportPadding)
  );
  const left = Math.min(Math.max(preferredLeft, leftMin), leftMax);
  const top = Math.max(6, Math.round(rect.bottom - 1));

  cornerContainer.style.top = `${top}px`;
  cornerContainer.style.left = `${left}px`;
  cornerContainer.style.right = "auto";
  cornerContainer.style.width = `${preferredWidth}px`;
}

function syncDashboardProfileMenuPosition() {
  if(!profileMenuOpen) return;
  if(!cornerContainer?.classList.contains("dashboard-pill-mode")) return;
  if(!activeDashboardProfileTrigger || !activeDashboardProfileTrigger.isConnected){
    closeCornerMenu();
    return;
  }
  positionCornerMenuFromDashboardPill(activeDashboardProfileTrigger);
}

window.addEventListener("resize", syncDashboardProfileMenuPosition);
window.addEventListener("scroll", syncDashboardProfileMenuPosition, true);

function toggleDashboardProfileMenuFromPill(trigger){
  if(!trigger || !cornerContainer) return;

  const isDashboardMenuOpen =
    profileMenuOpen &&
    cornerContainer.classList.contains("dashboard-pill-mode");

  if(isDashboardMenuOpen){
    closeCornerMenu();
    return;
  }

  if (activeDashboardProfileTrigger && activeDashboardProfileTrigger !== trigger) {
    activeDashboardProfileTrigger.classList.remove("menu-open");
    activeDashboardProfileTrigger.setAttribute("aria-expanded", "false");
  }
  activeDashboardProfileTrigger = trigger;
  activeDashboardProfileTrigger.classList.add("menu-open");
  activeDashboardProfileTrigger.setAttribute("aria-expanded", "true");
  watchDashboardProfileTriggerSize(activeDashboardProfileTrigger);
  cornerContainer.classList.add("dashboard-pill-mode");
  document.body.classList.add("dashboard-profile-menu-open");
  positionCornerMenuFromDashboardPill(trigger);
  openCornerMenu();
}


