function carryOverPendings() {

  const today = formatLocalDate(new Date());
  const dates = Object.keys(tasks);
  let changed = false;

  dates.forEach(dateKey => {

    // 🔒 evitar tocar el día actual
    if (dateKey === today) return;

    if (dateKey < today) {

      const dayTasks = Array.isArray(tasks[dateKey]) ? tasks[dateKey] : [];
      captureDailyCompletionSnapshot(dateKey, dayTasks);
      const pending = dayTasks.filter(t => !t.done);

      if (pending.length > 0) {

        if (!tasks[today]) tasks[today] = [];

        // 🔥 mover pendientes a hoy
        // 🔒 evitar duplicados en hoy
        const existingTexts = new Set((tasks[today] || []).map(t => t.text));

        const toMove = pending.filter(t => !existingTexts.has(t.text));

        if (toMove.length > 0) {
          tasks[today] = [
            ...toMove,
            ...(tasks[today] || [])
          ];

          changed = true;
        }

        tasks[dateKey] = dayTasks.filter(t => t.done);
      }

      // 🔥 si ya no quedan tareas en ese día → eliminar
      if (!Array.isArray(tasks[dateKey]) || tasks[dateKey].length === 0) {
        delete tasks[dateKey];
      }

    }

  });

  if (changed) save();
}

function cleanPastDays() {

  const today = formatLocalDate(new Date());
  let changed = false;

  Object.keys(tasks).forEach(dateKey => {

    if (dateKey < today) {
      delete tasks[dateKey];
      changed = true;
    }

  });

  if (changed) {
    save();
  }

}

function renderMiniCalendar() {
  const container = document.getElementById("miniCalendar");
  if (!container) return;

  const year = currentCalendarDate.getFullYear();
  const month = currentCalendarDate.getMonth();

  const firstDay = new Date(year, month, 1);
  const lastDay = new Date(year, month + 1, 0);

  let startDay = firstDay.getDay();

  // Convertir para que la semana empiece en Lunes
  startDay = (startDay === 0) ? 6 : startDay - 1;
  const totalDays = lastDay.getDate();

  const monthName = currentCalendarDate.toLocaleDateString("es-ES", { month: "long" });
  const monthTitle =
    monthName.charAt(0).toUpperCase() + monthName.slice(1);

  const weekdays = ["L","M","M","J","V","S","D"];

  let html = `
    <div class="month-header">
      <button class="month-nav-btn" id="prevMonth">‹</button>
      <div class="month-title">${monthTitle} ${year}</div>
      <button class="month-nav-btn" id="nextMonth">›</button>
    </div>

    <div class="weekdays">
      ${weekdays.map(d => `<div>${d}</div>`).join("")}
    </div>

    <div class="days">
  `;

  // DÍAS DEL MES ANTERIOR
  const prevLastDay = new Date(year, month, 0).getDate();

  for (let i = startDay - 1; i >= 0; i--) {
    html += `
      <div class="day other-month">
        ${prevLastDay - i}
      </div>
    `;
  }

  for (let d = 1; d <= totalDays; d++) {
    const today = new Date();

    const isToday =
      d === today.getDate() &&
      month === today.getMonth() &&
      year === today.getFullYear();

    const dateObj = new Date(year, month, d);
    const dateStr = formatLocalDate(dateObj);

    const todayStr = formatLocalDate(new Date());

    const hasTasks =
      dateStr >= todayStr &&
      tasks[dateStr] &&
      tasks[dateStr].some(t => !t.done);

    html += `
      <div class="day ${isToday ? "today" : ""}" data-date="${dateStr}">
        <span class="day-number">${d}</span>
        ${hasTasks && !isToday ? `<span class="dot"></span>` : ""}
      </div>
    `;
  }

  // DÍAS DEL MES SIGUIENTE
  const totalCells = startDay + totalDays;
  const nextDays = (7 - (totalCells % 7)) % 7;

  for (let i = 1; i <= nextDays; i++) {
    html += `
      <div class="day other-month">
        ${i}
      </div>
    `;
  }

  html += `</div>`;

  container.innerHTML = html;

  // ⬅️ Después de renderizar el HTML, volvemos a enganchar los botones

  const prevMonthBtn = document.getElementById("prevMonth");
  const nextMonthBtn = document.getElementById("nextMonth");

  if (prevMonthBtn) {
    prevMonthBtn.addEventListener("click", () => {
      currentCalendarDate.setMonth(currentCalendarDate.getMonth() - 1);
      renderMiniCalendar();
    });
  }

  if (nextMonthBtn) {
    nextMonthBtn.addEventListener("click", () => {
      currentCalendarDate.setMonth(currentCalendarDate.getMonth() + 1);
      renderMiniCalendar();
    });
  }
  const dayEls = container.querySelectorAll(".day:not(.other-month)");

  dayEls.forEach(dayEl => {
    dayEl.addEventListener("click", () => {

      const dateStr = dayEl.dataset.date;
      const todayStr = formatLocalDate(new Date());

      if (dateStr < todayStr) {
        showToast("No es posible crear tareas en días pasados");
        return;
      }

      const isMobile = window.innerWidth <= 900;

      // 🔥 Si es mobile y la sidebar está abierta → cerrarla
      if (isMobile && !sidebar.classList.contains("collapsed")) {
        sidebar.classList.add("collapsed");
      }

      openDayModal(dateStr);
    });
  });
}



function openDayModal(dateStr) {

  const existing = document.getElementById("dayOverlay");
  if (existing) existing.remove();

  const overlay = document.createElement("div");
  overlay.className = "overlay open";
  overlay.id = "dayOverlay";
  overlay.classList.add("day-overlay-cardless");

  const [year, month, day] = dateStr.split("-").map(Number);
  const selectedDate = new Date(year, month - 1, day);
  const column = createDayColumn(selectedDate);
  column.classList.add("day-overlay-column");

  const closeButton = document.createElement("button");
  closeButton.className = "day-column-close";
  closeButton.type = "button";
  closeButton.setAttribute("aria-label", "Cerrar vista del día");
  closeButton.innerHTML = `
    <svg viewBox="0 0 24 24" fill="none" aria-hidden="true">
      <path d="M6 6 18 18" stroke="currentColor" stroke-width="2.1" stroke-linecap="round"/>
      <path d="M18 6 6 18" stroke="currentColor" stroke-width="2.1" stroke-linecap="round"/>
    </svg>
  `;
  closeButton.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    overlay.remove();
    init(); // 🔥 refresca las 7 columnas
  });

  column.appendChild(closeButton);
  overlay.appendChild(column);
  document.body.appendChild(overlay);

  overlay.addEventListener("click", e => {
    if (e.target === overlay) {
      overlay.remove();
      init(); // 🔥 refresca board
    }
  });
}

function updateDayModalTaskCount(dateStr){
  const overlayOpen = !!document.querySelector("#dayOverlay.day-overlay-cardless");
  if (!overlayOpen) return;
  if (!dateStr) return;
}

